def _is_quiet_night(now: datetime | None = None) -> bool:
    """Quiet night window: 20:00~07:30 (no push; store only)."""
    now = now or _now_kst()
    t = now.time()
    return (t >= dtime(20, 0)) or (t < dtime(7, 30))
