# v40.0-#9: 이벤트 유형별 승률 분리
# ============================================================
def get_signal_type_stats(signal_log_data: dict = None) -> dict:
    """신호 유형별 승률·수익률 통계 반환.
    반환: {signal_type: {count, wins, win_rate, avg_pnl}}
    """
    try:
        if signal_log_data is None:
            signal_log_data = _read_json_locked(
                os.path.join(DATA_DIR, "signal_log.json"))
        if not isinstance(signal_log_data, dict):
            return {}

        stats = {}
        for _k, rec in signal_log_data.items():
            if not isinstance(rec, dict):
                continue
            st = rec.get("status", "")
            if st not in ("수익", "손실", "본전"):
                continue
            sig = rec.get("signal_type", "UNKNOWN")
            s = stats.setdefault(sig, {"count": 0, "wins": 0, "sum_pnl": 0.0})
            s["count"] += 1
            _sync_record_pnl_fields(rec)
            pnl = _effective_pnl_pct(rec, 0.0)
            s["sum_pnl"] += pnl
            if pnl > 0:
                s["wins"] += 1

        result = {}
        for sig, s in stats.items():
            if s["count"] < 3:
                continue
            result[sig] = {
                "count": s["count"],
                "wins": s["wins"],
                "win_rate": round(s["wins"] / s["count"] * 100),
                "avg_pnl": round(s["sum_pnl"] / s["count"], 1),
            }
        return result
    except Exception:
        return {}


def _format_signal_type_stats_line(stats: dict) -> str:
    """신호 유형별 승률을 브리핑용 한 줄로 포맷."""
    if not stats:
        return ""
    label_map = {
        "UPPER_LIMIT": "상한가", "NEAR_UPPER": "상한가근접", "SURGE": "급등",
        "EARLY_DETECT": "조기포착", "MID_PULLBACK": "눌림목",
        "ENTRY_POINT": "눌림목진입", "STRONG_BUY": "강력매수",
    }
    parts = []
    for sig, s in sorted(stats.items(), key=lambda x: -x[1]["count"]):
        label = label_map.get(sig, sig)
        emoji = "🔴" if s["win_rate"] >= 60 else ("🟡" if s["win_rate"] >= 40 else "🔵")
        parts.append(f"{emoji}{label} {s['win_rate']}%({s['count']}건)")
    return "  ".join(parts[:5])



# [v41.84] 파일 I/O 안전성

# [v41.84] 캐시 메모리 정리
CACHE_TTL_SECONDS = 3600
MAX_CACHE_SIZE = 5000
_exec_speed_cache = {}  # [v41.85] 모듈 레벨 선언 누락 수정 (NameError 방지)

def _purge_stale_entry_watch_hits() -> int:
    """v71: 장중 30분마다 _entry_watch에서 stale entry_hit 제거.
    기존: 재시작 시 _load_entry_watch_active()에서만 정리 → 장 중 쌓인 stale hit이
    _collect_actionable_position_limit_codes()에 의해 23~26개 유령 보유로 오카운트됨.
    수정: clean_expired_cache() 호출 시 함께 재검증해 장중에도 실시간 정리.
    """
    global _entry_watch
    if not isinstance(_entry_watch, dict) or not _entry_watch:
        return 0
    try:
        now_ts = time.time()
        siglog_data = _read_json_safe(SIGNAL_LOG_FILE, {})
        latest_by_code = _build_latest_tracking_by_code(siglog_data)
        purged = []
        for key, watch in list(_entry_watch.items()):
            if not isinstance(watch, dict):
                continue
            if not (watch.get("entry_hit") or watch.get("entry_hit_locked")):
                continue
            code = normalize_stock_code(watch.get("code"))
            latest_rec = latest_by_code.get(code) if code else None
            if not _is_actionable_entry_watch(watch, latest_rec=latest_rec, now_ts=now_ts):
                purged.append(key)
        for key in purged:
            w = _entry_watch.pop(key, None)
            if w:
                code = normalize_stock_code(w.get("code", ""))
                print(f"  🗑 stale entry_hit 정리: {w.get('name', code)} ({code}) key={key}")
        if purged:
            _save_entry_watch_active()
        return len(purged)
    except Exception as e:
        print(f"  ⚠️ stale entry_hit 정리 오류: {e}")
        return 0


def clean_expired_cache():
    global _sector_cache, _daily_cache, _exec_speed_cache
    current_ts = time.time()
    cleaned = 0
    for cache in [_sector_cache, _daily_cache, _exec_speed_cache]:
        if not isinstance(cache, dict):
            continue
        expired = [k for k, v in cache.items()
                   if isinstance(v, dict) and current_ts - v.get("ts", 0) > CACHE_TTL_SECONDS]
        for k in expired: del cache[k]; cleaned += 1
        if len(cache) > MAX_CACHE_SIZE:
            sortable = [(k, v) for k, v in cache.items() if isinstance(v, dict)]
            for k, _ in sorted(sortable, key=lambda x: x[1].get("ts", 0))[:10]:
                del cache[k]; cleaned += 1
    if cleaned > 0: print(f"[캐시 정리] {cleaned}개")
    # v71: 장중 stale entry_hit 정리 연결
    _purge_stale_entry_watch_hits()

def reset_daily_caches():
    global _daily_cache, _exec_speed_cache
    _daily_cache = {}
    _exec_speed_cache = {}

# [v41.84] NXT/KRX 명확화
def get_active_market_type() -> str:
    h, m = _now_kst().hour, _now_kst().minute
    if 8 <= h < 15 or (h == 15 and m < 30): return "KRX"
    if (h == 15 and m >= 40) or 16 <= h < 20 or h == 20: return "NXT"
    return "CLOSED"

def get_market_params(market_type: str, slot: str = "") -> dict:
    if market_type == "KRX": return KRX_TIME_PARAMS.get(slot, {})
    elif market_type == "NXT": return NXT_TIME_PARAMS.get(slot, {})
    return {}

# --- HOTFIX v37.3: safe AI response extractor (prevents KeyError: 'content') ---
def extract_ai_text(resp_json):
    """Safely extract analysis text from AI provider response."""
    try:
        # Anthropic-style: {"content":[{"text":"..."}]}
        content = resp_json.get("content")
        if isinstance(content, list) and content:
            t = content[0].get("text", "")
            if t:
                return str(t).strip()
    except Exception:
        pass
    try:
        # OpenAI-style: {"choices":[{"message":{"content":"..."}}]}
        choices = resp_json.get("choices")
        if isinstance(choices, list) and choices:
            msg = (choices[0].get("message") or {})
            t = msg.get("content", "")
            if t:
                return str(t).strip()
    except Exception:
        pass
    return ""


# .env 파일 자동 로드 (python-dotenv 없어도 직접 파싱)
def _load_dotenv(path: str = ".env"):
    try:
        with open(path) as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#") or "=" not in line: continue
                k, v = line.split("=", 1)
                os.environ.setdefault(k.strip(), v.strip().strip('"').strip("'"))
    except FileNotFoundError: pass
_load_dotenv()

