# ============================================================
# ⑮ 20일 이동평균 괴리율 (Renaissance 평균회귀)
# ============================================================
def get_ma20_deviation(code: str) -> float:
    """현재가 기준 20일 이평 대비 괴리율 (%) — 음수면 이평 아래"""
    items = get_daily_data(code, 30)
    if len(items) < 20:
        return 0.0
    ma20  = sum(i["close"] for i in items[-20:]) / 20
    price = items[-1]["close"]
    return round((price - ma20) / ma20 * 100, 2) if ma20 else 0.0

# ============================================================
# ⑯ 코스피 상대강도 (시장 중립 필터)
# ============================================================
_kospi_cache = {"change": 0.0, "ts": 0}

def get_kospi_change() -> float:
    """코스피 당일 등락률"""
    if time.time() - _kospi_cache["ts"] < 300:
        return _kospi_cache["change"]
    try:
        url    = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-index-price"
        params = {"FID_COND_MRKT_DIV_CODE":"U","FID_INPUT_ISCD":KOSPI_CODE}
        data   = _safe_get(url, "FHPUP02100000", params)
        o      = data.get("output", {})
        chg    = float(o.get("bstp_nmix_prdy_ctrt", 0))
        _kospi_cache["change"] = chg
        _kospi_cache["ts"]     = time.time()
        return chg
    except Exception:
        return 0.0

def get_relative_strength(stock_change: float) -> float:
    """종목 등락률 / 코스피 등락률 = 상대강도"""
    kospi = get_kospi_change()
    if not kospi or kospi == 0:
        return stock_change  # 코스피 보합이면 그냥 종목 등락률
    return round(stock_change / abs(kospi), 2)

# ============================================================
# ⑰ 거래량 표준편차 Z-score (통계적 이상 탐지)
# ============================================================
def get_volume_zscore(code: str, today_vol: int) -> float:
    """오늘 거래량의 Z-score (과거 20일 기준)"""
    items = get_daily_data(code, 30)
    vols  = [i["vol"] for i in items[-20:] if i["vol"]]
    if len(vols) < 5:
        return 0.0
    mean = sum(vols) / len(vols)
    std  = math.sqrt(sum((v - mean) ** 2 for v in vols) / len(vols))
    return round((today_vol - mean) / std, 2) if std > 0 else 0.0

# ============================================================
# ⑭ 눌림목 실행 계층 / 분류 헬퍼
# ============================================================
MID_PULLBACK_BUCKET_LABELS = {
    "weekly_monthly_trend": "월·주 추세형",
    "daily_trend": "일봉 추세형",
    "gap_first_pullback": "갭 후 첫 눌림형",
    "intraday_reclaim": "분봉 재개형",
}

MID_PULLBACK_BUCKET_A_GUIDE = {
    "weekly_monthly_trend": "섹터/수급/거래량 중 2개 이상 확증",
    "daily_trend": "섹터 또는 재상승 포함 3개 이상 확증",
    "gap_first_pullback": "갭 유지 + 거래량/섹터 포함 3개 이상 확증",
    "intraday_reclaim": "장중 재개 + 거래량/섹터/수급 포함 4개 이상 확증",
}

def _mid_pullback_grade_from_score(score: int, a_cut: int = 80) -> str:
    s = int(score or 0)
    a_cut = max(70, int(a_cut or 80))
    if s >= a_cut:
        return "A"
    if s >= 60:
        return "B"
    return "C"


def _grade_rank(grade: str) -> int:
    return {"A": 3, "B": 2, "C": 1}.get(str(grade or "C").upper(), 0)


def _classify_mid_pullback_setup(*, is_intraday: bool = False, resurge_mode: bool = False,
                                 pullback_days: int = 0, surge_pct: float = 0.0,
                                 pullback_pct: float = 0.0, gap_pct: float = 0.0) -> dict:
    if bool(is_intraday):
        bucket = "intraday_reclaim"
    elif abs(float(gap_pct or 0.0)) >= 3.0 and int(pullback_days or 0) <= 4:
        bucket = "gap_first_pullback"
    elif int(pullback_days or 0) >= 8 or float(surge_pct or 0.0) >= 45.0 or float(pullback_pct or 0.0) >= 25.0:
        bucket = "weekly_monthly_trend"
    else:
        bucket = "daily_trend"
    label = MID_PULLBACK_BUCKET_LABELS.get(bucket, "일봉 추세형")
    note_map = {
        "weekly_monthly_trend": "상위 추세 지속 속 눌림 후 재개",
        "daily_trend": "일봉 추세 지속 속 눌림 재개",
        "gap_first_pullback": "갭 발생 뒤 첫 눌림 재접근",
        "intraday_reclaim": "장중 눌림 뒤 체결 재개",
    }
    return {
        "mid_pullback_bucket": bucket,
        "mid_pullback_bucket_label": label,
        "mid_pullback_bucket_note": note_map.get(bucket, ""),
        "mid_pullback_a_guide": MID_PULLBACK_BUCKET_A_GUIDE.get(bucket, "확증 3개 이상"),
    }


def _get_mid_pullback_close_window_info(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or datetime.now()
    stage = ""
    close_hhmm = None
    if is_market_open():
        stage = "KRX"
        close_hhmm = 1530
    elif is_nxt_open():
        stage = "NXT"
        close_hhmm = 2000
    if not stage or close_hhmm is None:
        return {"stage": "", "is_close_window": False, "remain_min": 999, "window_min": 0, "penalty": 0}
    now_hhmm = now_dt.hour * 100 + now_dt.minute
    if now_hhmm > close_hhmm:
        remain_min = 0
    else:
        ch, cm = divmod(close_hhmm, 100)
        close_dt = now_dt.replace(hour=ch, minute=cm, second=0, microsecond=0)
        remain_min = max(0, int((close_dt - now_dt).total_seconds() // 60))
    window_key = "mid_pullback_close_window_min_krx" if stage == "KRX" else "mid_pullback_close_window_min_nxt"
    window_min = int(_dynamic.get(window_key, 20 if stage == "KRX" else 25) or 0)
    gate_level = int(_dynamic.get("mid_pullback_close_gate_level", 1) or 0)
    is_close_window = remain_min <= max(0, window_min)
    penalty = gate_level if is_close_window else 0
    return {
        "stage": stage,
        "is_close_window": is_close_window,
        "remain_min": remain_min,
        "window_min": window_min,
        "penalty": penalty,
    }


def _get_mid_pullback_bucket_thresholds(bucket: str) -> tuple[int, int]:
    base_a = {
        "weekly_monthly_trend": 2,
        "daily_trend": 3,
        "gap_first_pullback": 3,
        "intraday_reclaim": 4,
    }
    base_b = {
        "weekly_monthly_trend": 1,
        "daily_trend": 2,
        "gap_first_pullback": 2,
        "intraday_reclaim": 2,
    }
    a_map = _safe_nested_dict(_dynamic, "mid_pullback_bucket_a_confirm_min", base_a)
    b_map = _safe_nested_dict(_dynamic, "mid_pullback_bucket_b_confirm_min", base_b)
    a_min = int(a_map.get(bucket, base_a.get(bucket, 3)) or base_a.get(bucket, 3))
    b_min = int(b_map.get(bucket, base_b.get(bucket, 1)) or base_b.get(bucket, 1))
    st = _get_intraday_capture_mode()
    if _intraday_capture_mode_active(st) and bucket in {"daily_trend", "gap_first_pullback", "intraday_reclaim"}:
        a_min = max(1, a_min - 1)
        b_min = max(0, b_min - 1)
    return max(1, a_min), max(0, b_min)


def _get_mid_pullback_execution_profile(result: dict) -> dict:
    sector_info = result.get("sector_info") or {}
    sector_bonus = int(sector_info.get("bonus", 0) or 0)
    core_hits = []
    support_hits = []
    if sector_bonus >= 3:
        core_hits.append("섹터강함")
    elif sector_bonus > 0:
        support_hits.append("섹터보통")
    if bool(result.get("direct_news_hit")):
        core_hits.append("직접뉴스")
    if bool(result.get("resurge_mode")):
        core_hits.append("재상승")
    if bool(result.get("is_intraday")):
        core_hits.append("장중돌파")
    if bool(result.get("turnaround_confirmed")):
        support_hits.append("수급전환")
    if float(result.get("rs", 0) or 0) >= RS_MIN:
        support_hits.append("상대강도")
    if float(result.get("vol_zscore", 0) or 0) >= VOL_ZSCORE_MIN:
        support_hits.append("거래량Z")
    if bool(result.get("vol_recovered")):
        support_hits.append("거래량회복")
    if bool(result.get("is_bullish")):
        support_hits.append("당일양봉")
    if float(result.get("volume_ratio", 0) or 0) >= 3.0:
        support_hits.append("거래량3배")
    if float(result.get("ma20_dev", -99) or -99) >= 0:
        support_hits.append("20일선회복")
    close_info = _get_mid_pullback_close_window_info()
    if close_info.get("is_close_window"):
        support_hits.append(f"{close_info.get('stage','')}마감근접")
    core_hits = list(dict.fromkeys(core_hits))
    support_hits = list(dict.fromkeys(support_hits))
    total_hits = list(dict.fromkeys(core_hits + support_hits))
    return {
        "core_hits": core_hits,
        "support_hits": support_hits,
        "total_hits": total_hits,
        "core_count": len(core_hits),
        "total_count": len(total_hits),
        "sector_bonus": sector_bonus,
        "close_info": close_info,
        "close_penalty": int(close_info.get("penalty", 0) or 0),
    }


def _is_mid_pullback_meta_reason(line: str) -> bool:
    t = str(line or "").strip()
    return t.startswith(("🧭 눌림 유형:", "🎯 실행 A 조건:", "⚠️ 실행 보정:", "🕒 장마감 근접:"))


def _apply_mid_pullback_execution_grade(result: dict) -> dict:
    if not isinstance(result, dict) or str(result.get("signal_type", "")).upper() != "MID_PULLBACK":
        return result
    pattern_grade = str(result.get("pattern_grade") or result.get("grade") or "C").upper()
    bucket = str(result.get("mid_pullback_bucket") or "daily_trend")
    profile = _get_mid_pullback_execution_profile(result)
    close_penalty = int(profile.get("close_penalty", 0) or 0)
    a_min, b_min = _get_mid_pullback_bucket_thresholds(bucket)
    req_a = a_min + close_penalty
    req_b = b_min + (1 if close_penalty >= 2 else 0)
    core_count = int(profile.get("core_count", 0) or 0)
    total_count = int(profile.get("total_count", 0) or 0)
    execution_grade = pattern_grade
    pattern_score = int(result.get("pattern_score_base", result.get("score", 0)) or 0)
    if pattern_grade == "A":
        if core_count >= 1 and total_count >= req_a:
            execution_grade = "A"
        elif total_count >= max(req_b, req_a - 1):
            execution_grade = "B"
        else:
            execution_grade = "C"
    elif pattern_grade == "B":
        # v71: 점수 95점↑ B등급 → 실질 A로 승격 (A기준 확장)
        # 로그상 98~129점 B등급이 외부알림 전량 차단되던 문제 해소
        if pattern_score >= 95 and total_count >= req_b:
            execution_grade = "A"
            result.setdefault("reasons", []).append(f"🔺 고점수 B→A 승격: {pattern_score}점 (임계 95점↑)")
        else:
            execution_grade = "B" if total_count >= req_b else "C"
    else:
        execution_grade = "C"

    reasons = [r for r in list(result.get("reasons") or []) if not _is_mid_pullback_meta_reason(r)]
    bucket_label = str(result.get("mid_pullback_bucket_label") or MID_PULLBACK_BUCKET_LABELS.get(bucket, "일봉 추세형"))
    reasons.append(f"🧭 눌림 유형: {bucket_label}")
    reasons.append(f"🎯 실행 A 조건: {MID_PULLBACK_BUCKET_A_GUIDE.get(bucket, '확증 3개 이상')}")
    close_info = profile.get("close_info") or {}
    if close_info.get("is_close_window"):
        reasons.append(f"🕒 장마감 근접: {close_info.get('stage','')} {int(close_info.get('remain_min', 0) or 0)}분 전")
    if execution_grade != pattern_grade:
        reason_labels = profile.get("core_hits") or profile.get("support_hits") or []
        note_reason = ", ".join(reason_labels[:2]) if reason_labels else "실행확증 부족"
        reasons.append(f"⚠️ 실행 보정: 패턴 {pattern_grade} → 현재 {execution_grade} ({note_reason})")
    result["reasons"] = reasons
    result["pattern_grade"] = pattern_grade
    result["execution_grade"] = execution_grade
    result["execution_profile"] = profile
    result["grade"] = execution_grade
    result["mid_close_stage"] = close_info.get("stage", "")
    result["mid_close_window_active"] = bool(close_info.get("is_close_window"))
    result["mid_close_remain_min"] = int(close_info.get("remain_min", 999) or 999)
    result["mid_execution_confirm_count"] = total_count
    result["mid_execution_core_count"] = core_count
    return result


def _finalize_mid_pullback_signal(result: dict) -> dict:
    if not isinstance(result, dict) or str(result.get("signal_type", "")).upper() != "MID_PULLBACK":
        return result
    ctx = _classify_mid_pullback_setup(
        is_intraday=bool(result.get("is_intraday")),
        resurge_mode=bool(result.get("resurge_mode")),
        pullback_days=int(result.get("pullback_days", 0) or 0),
        surge_pct=float(result.get("surge_pct", 0.0) or 0.0),
        pullback_pct=float(result.get("pullback_pct", 0.0) or 0.0),
        gap_pct=float(result.get("gap_pct", 0.0) or 0.0),
    )
    result.update(ctx)
    pattern_score = int(result.get("pattern_score_base", result.get("score", 0)) or 0)
    result["pattern_score_base"] = pattern_score
    a_cut = 80
    if _should_relax_general_a_threshold(
        "MID_PULLBACK",
        pattern_score,
        change_rate=float(result.get("change_rate", 0.0) or 0.0),
        vol_ratio=float(result.get("volume_ratio", 0.0) or 0.0),
        sector_info=result.get("sector_info") if isinstance(result.get("sector_info"), dict) else {},
        direct_news_hit=bool(result.get("direct_news_hit")),
        market=str(result.get("market", "") or ""),
        reasons=list(result.get("reasons") or []),
    ):
        a_cut = min(a_cut, INTRADAY_CAPTURE_RELAX_SCORE)
        result.setdefault("reasons", []).append(f"🏷 선행형 A게이트 자동확장 (80→{a_cut})")
    result["mid_pullback_a_cut"] = a_cut
    result["pattern_grade"] = _mid_pullback_grade_from_score(pattern_score, a_cut=a_cut)
    return _apply_mid_pullback_execution_grade(result)


# ============================================================
# ⑭ 눌림목 핵심 분석 함수
# ============================================================
def analyze_mid_pullback(code: str, name: str) -> dict:
    """
    퀀트펀드 눌림목 모멘텀 분석 (AQR 방식 응용)

    패턴:
      1단계: 1차 급등 확인 (20일 내 +15% 이상)
      2단계: 건강한 눌림 확인
             - 고점 대비 -10~40% 조정
             - 눌림 기간: 2~15일
             - 눌림 중 거래량 감소 (관심 유지되는 건강한 조정)
      3단계: 재상승 시작 신호
             - 당일 양봉 (종가 > 시가)
             - 거래량 회복 (눌림 평균의 1.5배 이상)
             - 20일선 회복 시작
      4단계: 섹터 동반 + 코스피 상대강도

    반환: grade(A/B/C), score, reasons, entry/stop/target
    """
    items = get_daily_data(code, MID_SURGE_LOOKBACK_DAYS + MID_PULLBACK_DAYS_MAX + 10)
    if len(items) < 10:
        return {}

    today  = items[-1]
    price  = today["close"]
    if price < 500:
        return {}

    _regime = get_market_regime()
    _regime_mult = float(_dynamic.get("regime_score_mult", 1.0) or 1.0)
    _regime_min_add = int(_dynamic.get("regime_min_add", 0) or 0)

    # ━━━ 1단계: 1차 급등 확인 ━━━
    # 최근 20일 내에서 저점 → 고점 상승률 계산
    lookback = items[-(MID_SURGE_LOOKBACK_DAYS + MID_PULLBACK_DAYS_MAX):-1]
    if not lookback:
        return {}

    surge_peak_idx  = -1
    surge_peak_price = 0
    surge_from_price = 0
    surge_pct        = 0

    for i in range(len(lookback) - 1, -1, -1):
        candidate_high = lookback[i]["high"]
        # 이 고점 이전의 저점 탐색 (최대 20일 이전)
        search_start = max(0, i - MID_SURGE_LOOKBACK_DAYS)
        base_low = min(lookback[j]["low"] for j in range(search_start, i+1) if lookback[j]["low"])
        if not base_low:
            continue
        pct = (candidate_high - base_low) / base_low * 100
        if pct >= _dynamic["mid_surge_min_pct"] and candidate_high > surge_peak_price:
            surge_peak_price = candidate_high
            surge_from_price = base_low
            surge_peak_idx   = i
            surge_pct        = round(pct, 1)

    if surge_peak_idx < 0 or surge_peak_price == 0:
        return {}  # 1차 급등 없음

    # ━━━ 2단계: 건강한 눌림 확인 ━━━
    # 급등 고점 이후 ~ 오늘까지의 데이터
    after_peak = lookback[surge_peak_idx+1:] + [today]
    if not after_peak:
        return {}

    pullback_low   = min(d["low"]   for d in after_peak if d["low"])
    pullback_days  = len(after_peak)
    pullback_pct   = round((surge_peak_price - pullback_low) / surge_peak_price * 100, 1)

    # 눌림 깊이·기간 검증
    if not (_dynamic["mid_pullback_min"] <= pullback_pct <= _dynamic["mid_pullback_max"]):
        return {}
    if not (MID_PULLBACK_DAYS_MIN <= pullback_days <= MID_PULLBACK_DAYS_MAX):
        return {}

    # 눌림 중 거래량 감소 여부 (건강한 눌림 = 거래량 줄면서 쉬는 것)
    surge_vols    = [d["vol"] for d in lookback[max(0,surge_peak_idx-3):surge_peak_idx+1] if d["vol"]]
    pullback_vols = [d["vol"] for d in after_peak[:-1] if d["vol"]]  # 오늘 제외
    avg_surge_vol   = sum(surge_vols)    / len(surge_vols)    if surge_vols    else 0
    avg_pullback_vol = sum(pullback_vols) / len(pullback_vols) if pullback_vols else 0
    vol_dried = avg_pullback_vol < avg_surge_vol * 0.7 if avg_surge_vol else False

    # ━━━ 3단계: 재상승 시작 신호 ━━━
    today_vol     = today["vol"]
    today_open    = today["open"]
    today_close   = today["close"]
    today_high    = today["high"]

    # 당일 양봉 확인
    is_bullish = today_close > today_open if today_open else False

    # 거래량 회복 (눌림 평균 대비)
    vol_recovered = (today_vol >= avg_pullback_vol * _dynamic["mid_vol_recovery"]) if avg_pullback_vol else False

    # 20일 이동평균 계산
    ma_items = items[-20:]
    ma20     = sum(i["close"] for i in ma_items) / len(ma_items) if len(ma_items) >= 20 else 0
    ma20_dev = round((today_close - ma20) / ma20 * 100, 1) if ma20 else 0

    # 이평 회복 시작 (20일선을 향해 올라오는 중)
    prev_close   = items[-2]["close"] if len(items) >= 2 else 0
    ma20_recovering = (today_close > prev_close and ma20_dev > -15) if prev_close and ma20 else False

    # 고점 대비 현재 위치 (반등 진행도)
    current_pullback = round((surge_peak_price - today_close) / surge_peak_price * 100, 1)

    # ━━━ 4단계: 스코어 계산 ━━━
    score   = 0
    reasons = []
    grade   = "C"
    sector_info: dict = {}
    sentiment: dict = {}

    # 1차 급등 강도
    if surge_pct >= 40:   score += 25; reasons.append(f"🚀 1차 급등 {surge_pct:.0f}% (강력)")
    elif surge_pct >= 25: score += 20; reasons.append(f"📈 1차 급등 {surge_pct:.0f}%")
    else:                 score += 15; reasons.append(f"📈 1차 급등 {surge_pct:.0f}%")

    # 눌림 품질 (건강한 눌림일수록 높은 점수)
    if vol_dried:
        score += 15; reasons.append(f"✅ 건강한 눌림 (거래량 감소 확인, -{pullback_pct:.0f}%)")
    else:
        score += 8;  reasons.append(f"🟡 눌림 {pullback_pct:.0f}% ({pullback_days}일간)")

    # 눌림 깊이 — 황금 구간 (15~30%)이 가장 이상적
    if 15 <= pullback_pct <= 30:
        score += 15; reasons.append(f"🎯 황금 눌림 구간 ({pullback_pct:.0f}%)")
    elif 10 <= pullback_pct < 15:
        score += 8;  reasons.append(f"🟡 얕은 눌림 ({pullback_pct:.0f}%)")
    else:
        score += 5;  reasons.append(f"🟡 깊은 눌림 ({pullback_pct:.0f}%)")

    # 재상승 신호
    if is_bullish:
        score += 10; reasons.append("🕯 당일 양봉 확인")
    if vol_recovered:
        vol_ratio_vs_pb = round(today_vol / avg_pullback_vol, 1) if avg_pullback_vol else 0
        score += 15; reasons.append(f"💥 거래량 회복 (눌림 평균 대비 {vol_ratio_vs_pb:.1f}배)")
    if ma20_recovering:
        score += 10; reasons.append(f"📊 20일선 회복 중 (현재 {ma20_dev:+.1f}%)")

    # ━━━ 4-1: 코스피 상대강도 체크 ⑯ ━━━
    kospi_chg = get_kospi_change()
    today_chg  = round((today_close - (items[-2]["close"] if len(items)>=2 else today_close))
                       / (items[-2]["close"] or today_close) * 100, 2)
    rs = get_relative_strength(today_chg)
    if rs >= RS_MIN:
        score += 10; reasons.append(f"💪 코스피 상대강도 {rs:.1f}배 (코스피 {kospi_chg:+.1f}%)")

    # ━━━ 4-2: 거래량 Z-score ⑰ ━━━
    z = get_volume_zscore(code, today_vol)
    if z >= VOL_ZSCORE_MIN:
        score += 10; reasons.append(f"📊 거래량 이상 급증 (Z-score {z:.1f}σ)")

    # ━━━ 4-3: 20일선 괴리율 ⑮ ━━━
    if MA20_DISCOUNT_MAX <= ma20_dev <= MA20_DISCOUNT_MIN:
        score += 5; reasons.append(f"📐 20일선 저점 근접 ({ma20_dev:+.1f}%)")

    # ━━━ 4-4: 해외 한국 ETF(EWY/FLKR) 장전 심리 + 섹터 차등 보정 ━━━
    try:
        kr_adj, kr_reason = calc_korea_etf_score_adj(code, name, "MID_PULLBACK", "")
        if kr_adj != 0:
            score += kr_adj
            reasons.append(kr_reason)
    except Exception as _e:
        _log_error(f"mid_pullback_korea_etf({code})", _e)

    # ━━━ 4-5: NXT 신뢰도 보정 ━━━
    nxt_delta, nxt_reason = 0, ""
    try:
        nxt_delta, nxt_reason = nxt_score_bonus(code)
        if nxt_delta != 0:
            _w_nxt = _dynamic.get("feat_w_nxt", 1.0)
            score += int(nxt_delta * _w_nxt)
            if nxt_reason: reasons.append(nxt_reason)
    except Exception: pass

    # 최소 조건: 양봉 + 거래량 회복 둘 다 없으면 재상승 미확인
    if not is_bullish and not vol_recovered:
        return {}

    try:
        sentiment = detect_foreign_institution_turnaround(code)
        if sentiment.get("foreign_turnaround") and sentiment.get("institution_buying"):
            score += int(sentiment.get("score_bonus", 0) or 0)
            reasons.append(f"🔄 외국인 음→양 전환 + 기관 순매수 (+{int(sentiment.get('score_bonus', 0) or 0)}점)")
    except Exception:
        pass

    score, reasons, similar_pattern_stats = _apply_similar_pattern_score(
        score, reasons, code, "MID_PULLBACK", today_chg, round(today_vol / avg_surge_vol, 1) if avg_surge_vol else 0, weight_mode="weak"
    )

    if _regime_mult != 1.0:
        score = int(round(score * _regime_mult))
    if _regime.get("mode", "normal") == "crash":
        return {}
    if _regime.get("mode", "normal") != "normal":
        reasons.append(f"🌎 {regime_label()} 필터: 최소점수 +{_regime_min_add}점 / 점수배율 x{_regime_mult:.2f}")

    # 등급 결정
    _grade_a = 80 + _regime_min_add
    _grade_b = 60 + _regime_min_add
    _grade_c = 45 + _regime_min_add
    if score >= _grade_a:   grade = "A"
    elif score >= _grade_b: grade = "B"
    elif score >= _grade_c: grade = "C"
    else:             return {}  # 점수 미달

    # 손절·목표가
    entry = today_close
    stop, target, stop_pct, target_pct, atr_used = calc_stop_target(code, entry, signal_type="MID_PULLBACK")

    _mid_tf_block = _should_block_multi_tf_downtrend_capture(code, "MID_PULLBACK", signal_meta={"score": score, "change_rate": today_chg, "vol_ratio": round(today_vol / avg_surge_vol, 1) if avg_surge_vol else 0, "sector_info": sector_info, "direct_news_hit": False, "resurge_mode": False, "is_intraday": False, "rs": rs, "vol_zscore": z, "vol_recovered": vol_recovered, "is_bullish": is_bullish, "turnaround_confirmed": bool(sentiment.get("foreign_turnaround") and sentiment.get("institution_buying"))})
    if _mid_tf_block.get("block"):
        _ctx = _mid_tf_block.get("context", {}) or {}
        _log_suppressed_alert(
            code, name,
            _mid_tf_block.get("reason", "주봉·일봉 동반 하락 추세 차단"),
            "MID_PULLBACK",
            {
                "daily_ret20": _ctx.get("daily_ret20", 0.0),
                "weekly_ret8": _ctx.get("weekly_ret8", 0.0),
                "daily_flags": _ctx.get("daily_flags", 0),
                "weekly_flags": _ctx.get("weekly_flags", 0),
                "change_rate": today_chg,
                "score": score,
            },
        )
        return {}

    return {
        "code": code, "name": name,
        "price": today_close, "change_rate": today_chg,
        "volume_ratio": round(today_vol / avg_surge_vol, 1) if avg_surge_vol else 0,
        "signal_type": "MID_PULLBACK",
        "grade": grade, "score": score,
        "surge_pct":     surge_pct,
        "pullback_pct":  pullback_pct,
        "pullback_days": pullback_days,
        "current_pullback": current_pullback,
        "vol_dried":     vol_dried,
        "vol_recovered": vol_recovered,
        "is_bullish":    is_bullish,
        "ma20_dev":      ma20_dev,
        "rs":            rs,
        "vol_zscore":    z,
        "similar_pattern_stats": similar_pattern_stats,
        "entry_price":   entry,
        "stop_loss":     stop, "target_price": target,
        "stop_pct":      stop_pct, "target_pct": target_pct,
        "atr_used":      atr_used,
        "sector_info":   sector_info,
        "reasons":       reasons,
        "detected_at":   datetime.now(),
        "market_regime_label": regime_label(),
        "market_regime_mode": _regime.get("mode", "normal"),
    }

