def _read_json_safe(path: str, default):
    try:
        if not os.path.isfile(path):
            return default
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return default

def _save_preclose_gap_entry_watch() -> None:
    try:
        _write_json_atomic(PRECLOSE_GAP_ENTRY_WATCH_FILE, _preclose_gap_entry_watch if isinstance(_preclose_gap_entry_watch, dict) else {}, indent=2)
    except Exception:
        pass

def _load_preclose_gap_entry_watch() -> None:
    global _preclose_gap_entry_watch
    try:
        raw = _read_json_safe(PRECLOSE_GAP_ENTRY_WATCH_FILE, {})
        if not isinstance(raw, dict):
            _preclose_gap_entry_watch = {}
            return
        now_ts = time.time()
        restored = {}
        siglog_data = _read_json_safe(SIGNAL_LOG_FILE, {})
        latest_by_code = _build_latest_tracking_by_code(siglog_data)
        for key, watch in raw.items():
            if not isinstance(watch, dict):
                continue
            code = normalize_stock_code(watch.get("code"))
            deadline_ts = float(watch.get("deadline_ts", 0) or 0)
            if not code or (deadline_ts and now_ts >= deadline_ts):
                continue
            restored[str(key)] = watch
        _preclose_gap_entry_watch = restored
        if raw != restored:
            _save_preclose_gap_entry_watch()
    except Exception:
        _preclose_gap_entry_watch = {}

def _save_reentry_watch() -> None:
    try:
        _write_json_atomic(REENTRY_WATCH_FILE, _reentry_watch if isinstance(_reentry_watch, dict) else {}, indent=2)
    except Exception:
        pass

def _load_reentry_watch() -> None:
    global _reentry_watch
    try:
        raw = _read_json_safe(REENTRY_WATCH_FILE, {})
        if not isinstance(raw, dict):
            _reentry_watch = {}
            return
        now_ts = time.time()
        restored = {}
        for code, watch in raw.items():
            if not isinstance(watch, dict):
                continue
            norm = normalize_stock_code(code or watch.get("code"))
            ts = float(watch.get("ts", 0) or 0)
            if not norm:
                continue
            if ts and now_ts - ts > 60 * 60 * 48:
                continue
            entry = int(watch.get("entry", 0) or 0)
            stop = int(watch.get("stop", 0) or 0)
            target = int(watch.get("target", 0) or 0)
            stop_price = int(watch.get("stop_price", 0) or 0)
            restored[norm] = {
                "name": str(watch.get("name", "") or ""),
                "stop_price": stop_price,
                "entry": entry,
                "stop": stop,
                "target": target,
                "signal_type": str(watch.get("signal_type", "") or ""),
                "ts": ts or now_ts,
                "nxt_listed": bool(watch.get("nxt_listed", is_nxt_listed(norm))),
                "market_basis": str(watch.get("market_basis", "NXT" if is_nxt_listed(norm) else "KRX") or ("NXT" if is_nxt_listed(norm) else "KRX")),
            }
        _reentry_watch = restored
        if raw != restored:
            _save_reentry_watch()
    except Exception:
        _reentry_watch = {}

def _clear_reentry_watch_all() -> None:
    _reentry_watch.clear()
    _save_reentry_watch()

def _save_execution_setup_watch(force: bool = True) -> None:
    global _execution_setup_watch_last_persist_ts
    try:
        now_ts = time.time()
        min_interval = max(0, int(EXECUTION_SETUP_STATE_SAVE_MIN_INTERVAL_SEC or 0))
        if not force and min_interval > 0 and _execution_setup_watch_last_persist_ts:
            if now_ts - _execution_setup_watch_last_persist_ts < min_interval:
                return
        _write_json_atomic(EXECUTION_SETUP_WATCH_FILE, _execution_setup_watch if isinstance(_execution_setup_watch, dict) else {}, indent=2)
        _execution_setup_watch_last_persist_ts = now_ts
    except Exception:
        pass

def _load_execution_setup_watch() -> None:
    global _execution_setup_watch
    try:
        raw = _read_json_safe(EXECUTION_SETUP_WATCH_FILE, {})
        if not isinstance(raw, dict):
            _execution_setup_watch = {}
            return
        now_ts = time.time()
        restored = {}
        for key, watch in raw.items():
            if not isinstance(watch, dict):
                continue
            code = normalize_stock_code(watch.get("code"))
            expire_ts = float(watch.get("expire_ts", 0) or 0)
            if not code:
                continue
            if expire_ts and now_ts >= expire_ts:
                continue
            watch["code"] = code
            watch.setdefault("name", watch.get("name", code))
            watch.setdefault("signal_type", watch.get("signal_type", ""))
            watch.setdefault("registered_ts", now_ts)
            watch.setdefault("last_price", safe_int(watch.get("last_price", 0), 0))
            watch.setdefault("peak_price", safe_int(watch.get("peak_price", 0), 0))
            watch.setdefault("signal_log_key", str(watch.get("signal_log_key", key) or key))
            watch.setdefault("detect_date", str(watch.get("detect_date", "") or ""))
            watch.setdefault("detect_time", str(watch.get("detect_time", "") or ""))
            watch.setdefault("market_basis", str(watch.get("market_basis", "") or ""))
            watch.setdefault("stage", str(watch.get("stage", "") or ""))
            restored[str(key)] = watch
        _execution_setup_watch = restored
        if raw != restored:
            _save_execution_setup_watch()
    except Exception:
        _execution_setup_watch = {}

def _entry_watch_store_key(store: dict, base_key: str) -> str:
    key = str(base_key or "entry_watch")
    if key not in store:
        return key
    idx = 2
    while f"{key}__{idx}" in store:
        idx += 1
    return f"{key}__{idx}"

def _prune_entry_watch_store(raw: dict, keep_days: int) -> dict:
    if not isinstance(raw, dict):
        return {}
    now_ts = time.time()
    keep_sec = max(1, int(keep_days or 1)) * 86400
    out = {}
    for key, rec in raw.items():
        if not isinstance(rec, dict):
            continue
        ts = 0.0
        try:
            ts = float(rec.get("consumed_ts", 0) or rec.get("archived_ts", 0) or rec.get("registered_ts", 0) or 0)
        except Exception:
            ts = 0.0
        if ts and now_ts - ts > keep_sec:
            continue
        out[str(key)] = rec
    return out

def _save_entry_watch_active() -> None:
    try:
        _write_json_atomic(ENTRY_WATCH_ACTIVE_FILE, _entry_watch if isinstance(_entry_watch, dict) else {}, indent=2)
    except Exception:
        pass

def _load_entry_watch_active() -> None:
    global _entry_watch
    try:
        raw = _read_json_safe(ENTRY_WATCH_ACTIVE_FILE, {})
        if not isinstance(raw, dict):
            _entry_watch = {}
            return
        now_ts = time.time()
        siglog_data = _read_json_safe(SIGNAL_LOG_FILE, {})
        latest_by_code = _build_latest_tracking_by_code(siglog_data)
        restored = {}
        for key, watch in raw.items():
            if not isinstance(watch, dict):
                continue
            code = normalize_stock_code(watch.get("code"))
            if not code:
                continue
            state = str(watch.get("entry_watch_state", "active") or "active")
            if state != "active":
                continue
            expire_ts = float(watch.get("expire_ts", 0) or 0)
            if expire_ts and now_ts >= expire_ts:
                continue
            watch = dict(watch)
            watch["code"] = code
            latest_rec = latest_by_code.get(code)
            if (watch.get("entry_hit") or watch.get("entry_hit_locked")) and not _is_actionable_entry_watch(watch, latest_rec=latest_rec, now_ts=now_ts):
                continue
            watch["name"] = _resolve_stock_name(code, watch.get("name", code))
            watch.setdefault("signal_type", str(watch.get("signal_type", "") or ""))
            watch.setdefault("registered_ts", now_ts)
            watch.setdefault("signal_log_key", str(watch.get("signal_log_key", key) or key))
            watch.setdefault("detect_date", str(watch.get("detect_date", "") or ""))
            watch.setdefault("detect_time", str(watch.get("detect_time", "") or ""))
            watch.setdefault("first_detect_date", str(watch.get("first_detect_date", watch.get("detect_date", "")) or ""))
            watch.setdefault("notify_count", safe_int(watch.get("notify_count", 0), 0))
            watch.setdefault("miss_count", safe_int(watch.get("miss_count", 0), 0))
            watch.setdefault("peak_price", safe_int(watch.get("peak_price", 0), 0))
            watch.setdefault("low_price", safe_int(watch.get("low_price", watch.get("entry_price", 0)), 0))
            watch.setdefault("low_price_time", str(watch.get("low_price_time", "") or ""))
            watch.setdefault("volume_at_low", safe_int(watch.get("volume_at_low", 0), 0))
            watch.setdefault("volume_ratio_at_detect", float(watch.get("volume_ratio_at_detect", watch.get("volume_ratio", 0)) or 0))
            watch.setdefault("signal_strength_at_detect", str(watch.get("signal_strength_at_detect", "") or ""))
            watch.setdefault("execution_speed_at_detect", int(watch.get("execution_speed_at_detect", 0) or 0))
            watch.setdefault("pullback_ratio_at_register", float(watch.get("pullback_ratio_at_register", watch.get("pullback_reclaim_ratio", 0.0)) or 0.0))
            watch.setdefault("source", str(watch.get("source", "") or ""))
            watch.setdefault("dart_reliability_score", int(watch.get("dart_reliability_score", 0) or 0))
            watch.setdefault("shareholder_confirmation_date", str(watch.get("shareholder_confirmation_date", "") or ""))
            watch.setdefault("entry_price_at_detect", safe_int(watch.get("entry_price_at_detect", watch.get("entry_price", 0)), 0))
            watch.setdefault("pattern_grade_at_detect", str(watch.get("pattern_grade_at_detect", watch.get("pattern_grade", watch.get("grade", ""))) or ""))
            watch.setdefault("execution_grade_at_detect", str(watch.get("execution_grade_at_detect", watch.get("execution_grade", watch.get("grade", ""))) or ""))
            watch.setdefault("grade_at_detect", str(watch.get("grade_at_detect", watch.get("execution_grade_at_detect", watch.get("grade", ""))) or ""))
            watch.setdefault("entry_reference_only", False)
            watch.setdefault("entry_reference_market", "")
            watch.setdefault("entry_reference_reason", "")
            watch.setdefault("entry_reference_time", "")
            watch.setdefault("entry_reference_price", 0)
            watch["entry_watch_state"] = "active"
            restored[str(key)] = watch
        _entry_watch = restored
        if raw != restored:
            _save_entry_watch_active()
    except Exception:
        _entry_watch = {}

def _archive_entry_watch_record(log_key: str, watch: dict | None, consume_reason: str = "", final_status: str = "") -> None:
    if not isinstance(watch, dict):
        return
    try:
        now_ts = time.time()
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        payload = dict(watch)
        payload["entry_watch_state"] = "consumed"
        payload["consumed"] = True
        payload["consumed_at"] = now_s
        payload["consumed_ts"] = now_ts
        if consume_reason:
            payload["consume_reason"] = str(consume_reason)
        if final_status:
            payload["final_status"] = str(final_status)

        with _file_lock:
            consumed = _read_json_unlocked(ENTRY_WATCH_CONSUMED_FILE, {})
            if not isinstance(consumed, dict):
                consumed = {}
            consumed = _prune_entry_watch_store(consumed, ENTRY_WATCH_CONSUMED_KEEP_DAYS)
            ckey = _entry_watch_store_key(consumed, log_key)
            consumed[ckey] = payload
            _write_json_atomic_unlocked(
                ENTRY_WATCH_CONSUMED_FILE,
                _prune_entry_watch_store(consumed, ENTRY_WATCH_CONSUMED_KEEP_DAYS),
                indent=2,
            )

            archive = _read_json_unlocked(ENTRY_WATCH_ARCHIVE_FILE, {})
            if not isinstance(archive, dict):
                archive = {}
            archive = _prune_entry_watch_store(archive, ENTRY_WATCH_ARCHIVE_KEEP_DAYS)
            akey = _entry_watch_store_key(archive, log_key)
            archive[akey] = payload
            _write_json_atomic_unlocked(
                ENTRY_WATCH_ARCHIVE_FILE,
                _prune_entry_watch_store(archive, ENTRY_WATCH_ARCHIVE_KEEP_DAYS),
                indent=2,
            )
    except Exception:
        pass

def _entry_watch_final_status(watch: dict | None, default_status: str = "") -> str:
    watch = watch or {}
    if watch.get("entry_reference_market"):
        return "NXT참고도달"
    if watch.get("entry_blocked"):
        return "진입불가"
    if watch.get("entry_hit"):
        return default_status or "진입후종료"
    return default_status or "진입미달"

FAST_EXECUTION_SIGNAL_TYPES = {"EARLY_DETECT", "NEAR_UPPER", "SURGE", PRECLOSE_GAP_SIGNAL_TYPE}
ENTRY_EXECUTION_SIGNAL_TYPES = {"ENTRY_POINT"}
MID_EXECUTION_SIGNAL_TYPES = {"MID_PULLBACK"}
EXEC_SPEED_WINDOW_SEC = int(os.getenv("EXEC_SPEED_WINDOW_SEC", "90") or "90")
EXEC_SPEED_MIN_SAMPLES = int(os.getenv("EXEC_SPEED_MIN_SAMPLES", "3") or "3")
EXEC_SPEED_MICRO_TRADE_MIN_KRW = int(os.getenv("EXEC_SPEED_MICRO_TRADE_MIN_KRW", "300000") or "300000")
EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER = int(os.getenv("EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER", "20") or "20")
EXEC_SPEED_MICRO_TRADE_MIN_KRW_NXT = int(os.getenv("EXEC_SPEED_MICRO_TRADE_MIN_KRW_NXT", "150000") or "150000")
EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER_NXT = int(os.getenv("EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER_NXT", "10") or "10")
EXEC_SPEED_CONFIRM_MIN_SCORE_FAST = int(os.getenv("EXEC_SPEED_CONFIRM_MIN_SCORE_FAST", "48") or "48")
EXEC_SPEED_CONFIRM_MIN_SCORE_ENTRY = int(os.getenv("EXEC_SPEED_CONFIRM_MIN_SCORE_ENTRY", "40") or "40")
EXEC_SPEED_CONFIRM_MIN_DIP_SCORE = int(os.getenv("EXEC_SPEED_CONFIRM_MIN_DIP_SCORE", "45") or "45")
EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT = float(os.getenv("EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT", "0.20") or "0.20")
EXEC_SPEED_CONFIRM_MAX_PULLBACK_PCT = float(os.getenv("EXEC_SPEED_CONFIRM_MAX_PULLBACK_PCT", "3.2") or "3.2")
EXEC_SPEED_FILTER_MAX_RATIO = float(os.getenv("EXEC_SPEED_FILTER_MAX_RATIO", "0.72") or "0.72")
EXEC_SPEED_SETUP_EXPIRE_SEC = int(os.getenv("EXEC_SPEED_SETUP_EXPIRE_SEC", "1800") or "1800")
EXEC_SPEED_PREWARM_MAX_SEC   = int(os.getenv("EXEC_SPEED_PREWARM_MAX_SEC",   "120")  or "120")   # 포착 후 워밍 최대 기간(초)
EXEC_SPEED_PREWARM_MAX_CODES = int(os.getenv("EXEC_SPEED_PREWARM_MAX_CODES", "8")    or "8")     # 동시 워밍 최대 종목 수 (API 부담 제한)
EXEC_SPEED_RECENT_WINDOW_SEC = int(os.getenv("EXEC_SPEED_RECENT_WINDOW_SEC", "30") or "30")
EXEC_SPEED_STALE_WARN_SEC = int(os.getenv("EXEC_SPEED_STALE_WARN_SEC", "45") or "45")
_execution_snapshots: dict = {}
_exec_speed_prewarm: dict = {}          # code → registered_ts, 포착 직후 스냅샷 사전 누적용
_execution_setup_watch: dict = {}
_execution_setup_watch_last_persist_ts: float = 0.0


def _prune_execution_snapshots(code: str, now_ts: float | None = None) -> None:
    now_ts = float(now_ts or time.time())
    buf = _execution_snapshots.get(code)
    if not isinstance(buf, list):
        return
    cutoff = now_ts - max(EXEC_SPEED_WINDOW_SEC * 4, 360)
    _execution_snapshots[code] = [s for s in buf if float(s.get("ts", 0) or 0) >= cutoff][-80:]


def _get_exec_speed_micro_trade_threshold(price: int, market: str = "KRX", sample_ts: float | None = None) -> int:
    price = safe_int(price, 0)
    if price <= 0:
        return 0
    market_name = str(market or "KRX").upper()
    ts = float(sample_ts or time.time())
    try:
        local_dt = datetime.fromtimestamp(ts)
        afterhours_hint = (local_dt.hour > 15) or (local_dt.hour == 15 and local_dt.minute >= 30) or (local_dt.hour < 9)
    except Exception:
        afterhours_hint = False
    relaxed = market_name == "NXT" or afterhours_hint
    share_multiplier = EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER_NXT if relaxed else EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER
    min_krw = EXEC_SPEED_MICRO_TRADE_MIN_KRW_NXT if relaxed else EXEC_SPEED_MICRO_TRADE_MIN_KRW
    return max(int(price * max(1, share_multiplier)), int(min_krw))


def _record_execution_snapshot(code: str, payload: dict, market: str = "KRX") -> None:
    code = normalize_stock_code(code)
    if not code or not isinstance(payload, dict):
        return
    price = safe_int(payload.get("price", 0))
    today_vol = safe_int(payload.get("today_vol", 0))
    if price <= 0 or today_vol <= 0:
        return
    now_ts = time.time()
    buf = _execution_snapshots.setdefault(code, [])
    prev = buf[-1] if buf else {}
    prev_vol = safe_int(prev.get("today_vol", 0))
    vol_delta = max(today_vol - prev_vol, 0)
    trade_value_delta = int(vol_delta * price)
    prev_ts = float(prev.get("ts", 0) or 0)
    elapsed_sec = max(now_ts - prev_ts, 1.0) if prev_ts > 0 else 0.0
    trade_value_per_sec = float(trade_value_delta / elapsed_sec) if trade_value_delta > 0 and elapsed_sec > 0 else 0.0
    micro_threshold = _get_exec_speed_micro_trade_threshold(price, market=market, sample_ts=now_ts)
    sample = {
        "ts": now_ts,
        "market": market,
        "price": price,
        "today_vol": today_vol,
        "change_rate": float(payload.get("change_rate", 0.0) or 0.0),
        "ask_qty": safe_int(payload.get("ask_qty", 0)),
        "bid_qty": safe_int(payload.get("bid_qty", 0)),
        "vol_delta": vol_delta,
        "trade_value_delta": trade_value_delta,
        "elapsed_sec": round(elapsed_sec, 2),
        "trade_value_per_sec": round(trade_value_per_sec, 2),
        "micro_trade": bool(vol_delta > 0 and trade_value_delta < micro_threshold),
    }
    if prev and prev.get("price") == price and prev.get("today_vol") == today_vol:
        return
    buf.append(sample)
    _prune_execution_snapshots(code, now_ts)

def get_execution_speed_metrics(code: str, current_price: int | None = None, window_sec: int = EXEC_SPEED_WINDOW_SEC) -> dict:
    code = normalize_stock_code(code)
    now_ts = time.time()
    out = {
        "ready": False,
        "provisional": False,
        "execution_speed_score": 0,
        "dip_resilience_score": 0,
        "micro_trade_filtered_ratio": 0.0,
        "pullback_pct": 0.0,
        "recent_peak_price": safe_int(current_price, 0),
        "suggested_entry_price": safe_int(current_price, 0),
        "valid_samples": 0,
        "window_samples": 0,
        "amount_per_active": 0,
        "active_ratio": 0.0,
        "avg_bid_ask_ratio": 0.0,
        "trade_value_per_sec": 0,
        "recent_trade_value_per_sec": 0,
        "prior_trade_value_per_sec": 0,
        "acceleration_ratio": 1.0,
        "freshness_score": 0,
        "last_active_age_sec": 999,
        "recent_valid_samples": 0,
        "flow_state": "중립",
        "summary": "샘플 부족",
    }
    if not code:
        return out
    samples = [s for s in (_execution_snapshots.get(code) or []) if float(s.get("ts", 0) or 0) >= now_ts - window_sec]
    out["window_samples"] = len(samples)
    if len(samples) < 2:
        return out

    positive = [s for s in samples if int(s.get("vol_delta", 0) or 0) > 0]
    valid = [s for s in positive if not s.get("micro_trade")]
    out["valid_samples"] = len(valid)
    if positive:
        out["micro_trade_filtered_ratio"] = round(max(0.0, 1.0 - len(valid) / max(len(positive), 1)), 2)
    if len(valid) < 2:
        out["summary"] = "유효 체결 부족"
        return out

    prices = [safe_int(s.get("price", 0), 0) for s in samples if safe_int(s.get("price", 0), 0) > 0]
    peak_price = max(prices) if prices else safe_int(current_price, 0)
    last_price = safe_int(current_price, 0) or safe_int(samples[-1].get("price", 0), 0)
    out["recent_peak_price"] = peak_price
    out["pullback_pct"] = round((peak_price - last_price) / peak_price * 100, 2) if peak_price else 0.0

    valid_amounts = [int(s.get("trade_value_delta", 0) or 0) for s in valid]
    mean_amount = sum(valid_amounts) / max(len(valid_amounts), 1)
    mean_abs_dev = sum(abs(v - mean_amount) for v in valid_amounts) / max(len(valid_amounts), 1)
    consistency = max(0.0, 1.0 - (mean_abs_dev / mean_amount)) if mean_amount > 0 else 0.0

    flow_rates = []
    prev_ts = None
    for s in valid:
        ts = float(s.get("ts", 0) or 0)
        elapsed = float(s.get("elapsed_sec", 0) or 0)
        if elapsed <= 0 and prev_ts:
            elapsed = max(ts - prev_ts, 1.0)
        rate = float(int(s.get("trade_value_delta", 0) or 0)) / max(elapsed, 1.0) if elapsed > 0 else 0.0
        flow_rates.append(rate)
        prev_ts = ts or prev_ts
    mean_rate = sum(flow_rates) / max(len(flow_rates), 1)
    out["trade_value_per_sec"] = int(mean_rate)

    recent_window = max(15, min(window_sec, EXEC_SPEED_RECENT_WINDOW_SEC))
    recent_cutoff = now_ts - recent_window
    recent_rates = []
    prior_rates = []
    recent_valid_samples = 0
    last_valid_ts = 0.0
    prev_ts = None
    for s in valid:
        ts = float(s.get("ts", 0) or 0)
        elapsed = float(s.get("elapsed_sec", 0) or 0)
        if elapsed <= 0 and prev_ts:
            elapsed = max(ts - prev_ts, 1.0)
        rate = float(int(s.get("trade_value_delta", 0) or 0)) / max(elapsed, 1.0) if elapsed > 0 else 0.0
        if ts >= recent_cutoff:
            recent_rates.append(rate)
            recent_valid_samples += 1
        else:
            prior_rates.append(rate)
        if ts > last_valid_ts:
            last_valid_ts = ts
        prev_ts = ts or prev_ts

    recent_rate = sum(recent_rates) / max(len(recent_rates), 1) if recent_rates else mean_rate
    prior_rate = sum(prior_rates) / max(len(prior_rates), 1) if prior_rates else mean_rate
    accel_ratio = recent_rate / max(prior_rate, 1.0) if recent_rate > 0 and prior_rate > 0 else 1.0
    out["recent_trade_value_per_sec"] = int(recent_rate)
    out["prior_trade_value_per_sec"] = int(prior_rate)
    out["acceleration_ratio"] = round(accel_ratio, 2)
    out["recent_valid_samples"] = recent_valid_samples

    last_active_age_sec = max(0, int(now_ts - last_valid_ts)) if last_valid_ts > 0 else 999
    out["last_active_age_sec"] = last_active_age_sec
    if last_active_age_sec <= 10:
        freshness_score = 100
    elif last_active_age_sec <= 20:
        freshness_score = 85
    elif last_active_age_sec <= 35:
        freshness_score = 70
    elif last_active_age_sec <= EXEC_SPEED_STALE_WARN_SEC:
        freshness_score = 55
    elif last_active_age_sec <= 70:
        freshness_score = 35
    else:
        freshness_score = 15
    out["freshness_score"] = freshness_score

    if last_active_age_sec > EXEC_SPEED_STALE_WARN_SEC:
        flow_state = "정체"
    elif recent_valid_samples >= 2 and accel_ratio >= 1.25:
        flow_state = "가속"
    elif prior_rates and accel_ratio <= 0.80:
        flow_state = "둔화"
    else:
        flow_state = "유지"
    out["flow_state"] = flow_state

    bid_ratios = []
    for s in valid:
        ask_qty = safe_int(s.get("ask_qty", 0), 0)
        bid_qty = safe_int(s.get("bid_qty", 0), 0)
        if ask_qty > 0 and bid_qty > 0:
            bid_ratios.append(min(bid_qty / ask_qty, 3.0))
    avg_bid_ratio = sum(bid_ratios) / len(bid_ratios) if bid_ratios else 1.0
    out["avg_bid_ask_ratio"] = round(avg_bid_ratio, 2)
    active_ratio = len(valid) / max(len(samples), 1)
    out["active_ratio"] = round(active_ratio, 2)
    out["amount_per_active"] = int(mean_amount)

    dip_samples = [s for s in valid if peak_price > 0 and safe_int(s.get("price", 0), 0) <= int(peak_price * (1 - EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT / 100.0))]
    if dip_samples:
        dip_mean = sum(int(s.get("trade_value_delta", 0) or 0) for s in dip_samples) / max(len(dip_samples), 1)
        base_mean = mean_amount or 1.0
        dip_ratio = max(0.0, min(dip_mean / base_mean, 1.4))
        dip_score = int(min(100, max(0, round(dip_ratio * 100))))
    elif out["pullback_pct"] >= EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT:
        dip_score = 45
    else:
        dip_score = 35
    out["dip_resilience_score"] = dip_score

    if mean_amount >= 100_000_000:
        amount_score = 40
    elif mean_amount >= 50_000_000:
        amount_score = 35
    elif mean_amount >= 20_000_000:
        amount_score = 30
    elif mean_amount >= 10_000_000:
        amount_score = 24
    elif mean_amount >= 5_000_000:
        amount_score = 18
    elif mean_amount >= 2_000_000:
        amount_score = 12
    elif mean_amount >= 1_000_000:
        amount_score = 8
    else:
        amount_score = 4

    if mean_rate >= 8_000_000:
        pace_score = 15
    elif mean_rate >= 4_000_000:
        pace_score = 12
    elif mean_rate >= 2_000_000:
        pace_score = 10
    elif mean_rate >= 1_000_000:
        pace_score = 8
    elif mean_rate >= 500_000:
        pace_score = 5
    elif mean_rate >= 200_000:
        pace_score = 3
    else:
        pace_score = 0

    depth_score = min(len(valid) * 5, 15)
    active_score = min(int(active_ratio * 20), 20)
    consistency_score = min(int(consistency * 15), 15)
    bid_score = min(max(int((avg_bid_ratio - 0.8) * 8), 0), 10)
    freshness_bonus = min(max(int((freshness_score - 30) / 7), -3), 10)
    if accel_ratio >= 1.45:
        accel_bonus = 8
    elif accel_ratio >= 1.18:
        accel_bonus = 5
    elif accel_ratio <= 0.65:
        accel_bonus = -6
    elif accel_ratio <= 0.85:
        accel_bonus = -3
    else:
        accel_bonus = 0
    stale_penalty = -8 if last_active_age_sec > 60 else (-4 if last_active_age_sec > EXEC_SPEED_STALE_WARN_SEC else 0)

    speed_score = max(0, min(100, amount_score + pace_score + depth_score + active_score + consistency_score + bid_score + freshness_bonus + accel_bonus + stale_penalty))
    out["execution_speed_score"] = int(speed_score)

    suggested_entry = safe_int(last_price, 0)
    if peak_price and last_price:
        if out["pullback_pct"] < EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT:
            suggested_entry = int(peak_price * (1 - EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT / 100.0))
        else:
            suggested_entry = min(last_price, int(peak_price * (1 - min(out["pullback_pct"], EXEC_SPEED_CONFIRM_MAX_PULLBACK_PCT) / 100.0)))
    out["suggested_entry_price"] = _round_price_down(max(suggested_entry, 0)) if suggested_entry else 0

    ready_window_min = max(2, EXEC_SPEED_MIN_SAMPLES)
    ready_valid_min = max(2, EXEC_SPEED_MIN_SAMPLES - 1)
    flow_hint = f" / 흐름 {flow_state} / 최근체결 {last_active_age_sec}초전"
    if len(samples) >= ready_window_min and len(valid) >= ready_valid_min:
        out["ready"] = True
        out["summary"] = f"속도 {out['execution_speed_score']}점 / 눌림유지 {out['dip_resilience_score']}점{flow_hint}"
    else:
        out["provisional"] = True
        out["summary"] = f"예비판단 {out['execution_speed_score']}점 / 눌림유지 {out['dip_resilience_score']}점{flow_hint}"
    return out

def _tick_exec_speed_prewarm() -> None:
    """포착 직후 등록된 종목의 체결속도 스냅샷을 사전 누적 (진입가 도달 시 샘플 부족 최소화).

    run_scan() 1사이클(20초)마다 호출되며, check_entry_watch() 직전에 실행해
    진입가 도달 판단 전 스냅샷 상태를 최신으로 유지한다.
    - 샘플이 EXEC_SPEED_MIN_SAMPLES 이상이면 해당 종목 워밍 해제.
    - EXEC_SPEED_PREWARM_MAX_SEC 초 경과 시 자동 해제 (방치 방지).
    - API 부담 제한: 가장 최근 등록 종목 기준 최대 EXEC_SPEED_PREWARM_MAX_CODES개만 처리.
    """
    global _exec_speed_prewarm
    if not _exec_speed_prewarm:
        return
    now_ts = time.time()

    # 만료 정리
    expired_codes = [c for c, ts in list(_exec_speed_prewarm.items())
                     if now_ts - ts > EXEC_SPEED_PREWARM_MAX_SEC]
    for c in expired_codes:
        _exec_speed_prewarm.pop(c, None)
    if not _exec_speed_prewarm:
        return

    krx_ok = is_market_open()
    nxt_ok = is_nxt_open()

    # 최근 등록 순으로 최대 N개만 처리
    targets = sorted(_exec_speed_prewarm.items(), key=lambda x: x[1], reverse=True)
    targets = targets[:EXEC_SPEED_PREWARM_MAX_CODES]

    for code, _reg_ts in targets:
        # 현재 유효 샘플 수 확인
        samples = _execution_snapshots.get(code) or []
        recent_samples = [
            s for s in samples
            if float(s.get("ts", 0) or 0) >= now_ts - EXEC_SPEED_WINDOW_SEC
        ]
        recent_count = len(recent_samples)
        recent_valid_count = sum(
            1 for s in recent_samples
            if int(s.get("vol_delta", 0) or 0) > 0 and not s.get("micro_trade")
        )
        if recent_count >= max(2, EXEC_SPEED_MIN_SAMPLES) and recent_valid_count >= max(2, EXEC_SPEED_MIN_SAMPLES - 1):
            # 충분히 쌓임 → 워밍 해제
            _exec_speed_prewarm.pop(code, None)
            continue
        # 스냅샷 1회 추가 수집 (시장 상태에 따라 KRX/NXT 선택)
        try:
            if krx_ok:
                get_stock_price(code)
            elif nxt_ok and is_nxt_listed(code):
                get_nxt_stock_price(code)
        except Exception:
            pass


def _execution_score_label(score: int) -> str:
    s = int(score or 0)
    if s >= 80:
        return "강함"
    if s >= 65:
        return "양호"
    if s >= 50:
        return "보통"
    return "약함"


def _entry_execution_judgement(metrics: dict | None = None) -> tuple[str, str]:
    metrics = metrics or {}
    speed_score = int(metrics.get("execution_speed_score", 0) or 0)
    dip_score = int(metrics.get("dip_resilience_score", 0) or 0)
    filtered_ratio = float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0)
    freshness_score = int(metrics.get("freshness_score", 0) or 0)
    flow_state = str(metrics.get("flow_state", "중립") or "중립")
    last_active_age_sec = int(metrics.get("last_active_age_sec", 999) or 999)

    if not metrics.get("ready"):
        if metrics.get("provisional") and speed_score >= 68 and dip_score >= 55 and freshness_score >= 70 and flow_state in {"가속", "유지"}:
            return ("참고", f"🟡 예비판단상 체결 살아있음 — {flow_state}, 최근 유효체결 {last_active_age_sec}초 전")
        return ("참고", "⚠️ 체결속도 샘플 부족 — 진입 시 추가 확인")

    if last_active_age_sec > EXEC_SPEED_STALE_WARN_SEC or freshness_score < 40:
        return ("보류 우선", f"⚠️ 최근 체결이 끊김 — 마지막 유효체결 {last_active_age_sec}초 전")
    if speed_score >= 75 and dip_score >= 70 and filtered_ratio <= 0.60 and flow_state != "둔화":
        return ("진입 적합", f"✅ {flow_state} 흐름 유지 — 최근 유효체결 {last_active_age_sec}초 전")
    if speed_score < 40 or dip_score < 40 or filtered_ratio > 0.75:
        return ("보류 우선", "⚠️ 하락 중 체결 유지 약함 — 진입보류 우선")
    if flow_state == "둔화":
        return ("보통", f"🟡 체결은 이어지지만 둔화 중 — 최근 유효체결 {last_active_age_sec}초 전")
    return ("보통", f"🟡 체결속도는 보통 수준 — {flow_state}, 최근 유효체결 {last_active_age_sec}초 전")

# ── v41.66: 신호 강도 판정 ──
def _classify_signal_strength(watch: dict, exec_metrics: dict | None = None) -> str:
    """신호 강도를 '강한'/'보통'/'약한'으로 분류.
    기준: 등급(A/B/C) + 체결속도(진입적합/보통/보류) + 포착점수 종합."""
    grade = str(watch.get("grade", "B")).upper()
    score = int(watch.get("score", 0) or 0)
    exec_label, _ = _entry_execution_judgement(exec_metrics)
    # 등급 기반 기본 강도
    if grade == "A" and score >= 75:
        base = "강한"
    elif grade == "C" or score < 50:
        base = "약한"
    else:
        base = "보통"
    # 체결속도 보정
    if exec_label == "보류 우선" and base == "보통":
        base = "약한"
    elif exec_label == "진입 적합" and base == "보통":
        base = "강한"

    return base


_fi_turnaround_cache: dict[str, dict] = {}


def get_effective_volume_ratio(signal_type: str, current_time: str) -> float:
    """신호타입 × 시간대별 동적 거래량 기준.
    v66: NXT 장전(08시) 구간 추가 — 유동성이 적은 시간대이므로 기준 완화.
    """
    base_vol = {
        "UPPER_LIMIT": 3.0,
        "NEAR_UPPER": 5.0,
        "SURGE": 7.0,
        "EXECUTION_SPEED": 5.0,
        "DEFAULT": 5.0,
    }
    base = float(base_vol.get(str(signal_type or ""), base_vol["DEFAULT"]))
    time_str = str(current_time or "")
    if " " in time_str:
        time_str = time_str.split(" ")[-1]
    try:
        hour = int((time_str or "00:00:00").split(":")[0])
    except Exception:
        hour = datetime.now().hour
    if 8 <= hour < 9:
        # v66: NXT 장전 — 유동성 적어 거래량 배수가 높게 산출되므로 기준 완화
        time_adj = 0.7
    elif 9 <= hour < 10:
        time_adj = 1.3
    elif 10 <= hour < 14:
        time_adj = 1.0
    elif 14 <= hour < 15:
        time_adj = 0.85
    elif 15 <= hour < 16:
        # NXT 장후 초반 — 유동성 전환기
        time_adj = 0.8
    else:
        time_adj = 0.9
    required = max(2.0, min(base * time_adj, 10.0))
    return round(required, 1)


def get_dart_reliability_score(disclosure_type: str) -> int:
    score_map = {
        "회사합병결정": 3,
        "이사회의견서정정": 2,
        "첨부정정": 2,
        "자사주소각": 2,
        "주식소각": 2,
        "자기주식소각": 2,
        "유상증자": 1,
        "무상증자": 1,
        "기타": 0,
    }
    title = str(disclosure_type or "")
    for key, value in score_map.items():
        if key != "기타" and key in title:
            return value
    return score_map["기타"]


def detect_foreign_institution_turnaround(code: str) -> dict:
    now_ts = time.time()
    out = {"foreign_turnaround": False, "institution_buying": False, "score_bonus": 0}
    try:
        inv = get_investor_trend(code)
        foreign_now = safe_int(inv.get("foreign_net", 0), 0)
        institution_now = safe_int(inv.get("institution_net", 0), 0)
        prev = _fi_turnaround_cache.get(code, {}) if isinstance(_fi_turnaround_cache, dict) else {}
        prev_foreign = safe_int(prev.get("foreign_net", 0), 0)
        prev_ts = float(prev.get("ts", 0) or 0)
        foreign_turnaround = prev_ts > 0 and (now_ts - prev_ts) <= 1800 and prev_foreign < 0 < foreign_now
        institution_buying = institution_now > 0
        out = {
            "foreign_turnaround": foreign_turnaround,
            "institution_buying": institution_buying,
            "score_bonus": 10 if (foreign_turnaround and institution_buying) else 0,
            "foreign_net": foreign_now,
            "institution_net": institution_now,
        }
        _fi_turnaround_cache[code] = {"foreign_net": foreign_now, "institution_net": institution_now, "ts": now_ts}
    except Exception:
        pass
    return out


def check_liquidity(code: str, max_spread: int = 500, quote: dict | None = None) -> bool:
    try:
        q = dict(quote or {})
        if not q:
            q = get_stock_price(code)
        bid = safe_int(q.get("bid_price", 0), 0)
        ask = safe_int(q.get("ask_price", 0), 0)
        bid_qty = safe_int(q.get("bid_qty", 0), 0)
        ask_qty = safe_int(q.get("ask_qty", 0), 0)
        if bid and ask:
            spread = ask - bid
            if spread > max_spread or spread < 0:
                return False
            return True
        if bid_qty <= 0 and ask_qty <= 0:
            return True
        if bid_qty <= 0 or ask_qty <= 0:
            return False
        return True
    except Exception:
        return True


def should_skip_expiration_for_dart_watch(watch: dict) -> bool:
    try:
        source = str(watch.get("source", "") or "")
        if source not in ("DART", "DART_MERGER", "MERGER_ANNOUNCEMENT"):
            return False
        shareholder_date = str(watch.get("shareholder_confirmation_date", "") or "")
        if not shareholder_date:
            return False
        target_date = datetime.strptime(shareholder_date, "%Y-%m-%d").date()
        return (target_date - datetime.now().date()).days >= 0
    except Exception:
        return False


def get_rsi_5min(code: str) -> float:
    try:
        mins = _get_minute_data(code, count=30)
        closes = [safe_int(x.get("close", 0), 0) for x in mins if safe_int(x.get("close", 0), 0) > 0]
        if len(closes) < 15:
            return float(calc_indicators(code).get("rsi", 50) or 50)
        gains, losses = [], []
        for prev, cur in zip(closes[:-1], closes[1:]):
            diff = cur - prev
            gains.append(max(diff, 0))
            losses.append(abs(min(diff, 0)))
        period = min(14, len(gains))
        avg_gain = sum(gains[-period:]) / max(period, 1)
        avg_loss = sum(losses[-period:]) / max(period, 1)
        if avg_loss <= 0:
            return 100.0 if avg_gain > 0 else 50.0
        rs = avg_gain / avg_loss
        return round(100 - (100 / (1 + rs)), 1)
    except Exception:
        return 50.0


def get_current_volume(code: str) -> int:
    try:
        return safe_int(get_stock_price(code).get("today_vol", 0), 0)
    except Exception:
        return 0


def get_macd_histogram(code: str) -> float:
    try:
        mins = _get_minute_data(code, count=60)
        closes = [float(safe_int(x.get("close", 0), 0)) for x in mins if safe_int(x.get("close", 0), 0) > 0]
        if len(closes) < 35:
            return 0.0
        def _ema(seq, period):
            k = 2 / (period + 1)
            ema = seq[0]
            out = []
            for val in seq:
                ema = val * k + ema * (1 - k)
                out.append(ema)
            return out
        ema12 = _ema(closes, 12)
        ema26 = _ema(closes, 26)
        macd = [a - b for a, b in zip(ema12, ema26)]
        signal = _ema(macd, 9)
        return round(macd[-1] - signal[-1], 4)
    except Exception:
        return 0.0


def detect_hammer_or_bullish_engulfing(code: str) -> bool:
    try:
        mins = _get_minute_data(code, count=3)
        if len(mins) < 2:
            return False
        last = mins[-1]
        prev = mins[-2]
        prev_open = safe_int(prev.get("open", 0), 0)
        prev_close = safe_int(prev.get("close", 0), 0)
        last_open = safe_int(last.get("open", 0), 0)
        last_close = safe_int(last.get("close", 0), 0)
        body = abs(last_close - last_open)
        prev_body = abs(prev_close - prev_open)
        hammer_like = last_close >= last_open and body <= max(int(last_close * 0.01), 50)
        bullish_engulf = prev_close < prev_open and last_close > last_open and last_open <= prev_close and last_close >= prev_open and body >= prev_body
        return hammer_like or bullish_engulf
    except Exception:
        return False


def confirm_bottom_and_signal(watch: dict, current_price: int, current_data: dict) -> dict:
    result = {
        "is_bottom_confirmed": False,
        "should_send_signal": False,
        "signal_type": None,
        "reason": "",
    }
    try:
        volume_ratio = float(current_data.get("volume_ratio", watch.get("volume_ratio", 0)) or 0.0)
        exec_metrics = dict(current_data.get("execution_metrics") or watch.get("execution_metrics") or {})
        strength = _classify_signal_strength(watch, exec_metrics)
        low_price_time = watch.get("low_price_time") or ""
        if isinstance(low_price_time, datetime):
            low_dt = low_price_time
        else:
            try:
                low_dt = datetime.strptime(str(low_price_time), "%Y-%m-%d %H:%M:%S")
            except Exception:
                low_dt = datetime.now()
        essential_check = {
            "volume": volume_ratio >= 2.5,
            "strength": strength in ("강한",),
            "time": (datetime.now() - low_dt).total_seconds() <= 1800,
        }
        if not all(essential_check.values()):
            result["reason"] = "필수조건 미충족"
            return result
        result["is_bottom_confirmed"] = True
        bonus_score = 0
        sentiment = detect_foreign_institution_turnaround(watch.get("code", ""))
        if sentiment.get("foreign_turnaround") and sentiment.get("institution_buying"):
            bonus_score += 3
        if int(watch.get("dart_reliability_score", 0) or 0) > 0:
            bonus_score += 2
        if check_liquidity(watch.get("code", ""), max_spread=300, quote=current_data):
            bonus_score += 2
        if get_rsi_5min(watch.get("code", "")) <= 30:
            bonus_score += 2
        vol_now = get_current_volume(watch.get("code", ""))
        vol_prev_low = safe_int(watch.get("volume_at_low", vol_now), vol_now)
        if vol_now and vol_prev_low and vol_now < vol_prev_low * 0.7:
            bonus_score += 2
        if get_macd_histogram(watch.get("code", "")) > 0:
            bonus_score += 1
        if detect_hammer_or_bullish_engulfing(watch.get("code", "")):
            bonus_score += 1
        if bonus_score >= 3:
            result["should_send_signal"] = True
            result["signal_type"] = "entry_signal"
            result["reason"] = f"바닥 확인 + 재상승 신호 ({bonus_score}점)"
        else:
            result["should_send_signal"] = True
            result["signal_type"] = "watch_alert"
            result["reason"] = f"바닥 형성 확인, 재상승 대기중 ({bonus_score}점)"
        return result
    except Exception as e:
        result["reason"] = f"오류: {e}"
        return result


# ── v41.66: 1차/2차 분할 비중 규칙 ──
ENTRY_SPLIT_RULES = {
    "강한": {"phase1_pct": 45, "phase2_pct": 30, "reserve_pct": 25, "phase2_allowed": True},
    "보통": {"phase1_pct": 35, "phase2_pct": 25, "reserve_pct": 40, "phase2_allowed": True},
    "약한": {"phase1_pct": 0,  "phase2_pct": 0,  "reserve_pct": 100, "phase2_allowed": False},
}

def _get_entry_split_rule(strength: str) -> dict:
    """신호 강도별 분할진입 비중 규칙 반환."""
    return ENTRY_SPLIT_RULES.get(strength, ENTRY_SPLIT_RULES["보통"])


def _calc_avg_entry_price(phase1_price: int, phase2_price: int, phase1_pct: int, phase2_pct: int) -> int:
    """1차/2차 진입가 기반 평균단가 계산."""
    total_pct = phase1_pct + phase2_pct
    if total_pct <= 0:
        return phase1_price
    return int((phase1_price * phase1_pct + phase2_price * phase2_pct) / total_pct)


# ── v41.66: 2차 추가진입 판단 ──
def _judge_phase2_entry(watch: dict, cur: dict, price: int, exec_metrics: dict | None = None) -> dict:
    """2차 추가진입 가능/보류/금지 판단.
    반환: {"decision": "가능"/"보류"/"금지", "reasons": [...], "detail": str}
    4개 조건: 눌림유지 / 체결속도 / 손절여유 / 섹터모멘텀"""
    entry = watch.get("entry_price", 0)
    stop = watch.get("stop_loss", 0)
    reasons = []
    fail_count = 0
    if entry and price:
        drop_pct = (entry - price) / entry * 100
        if drop_pct <= 1.5:
            reasons.append("✅ 눌림 유지 (진입가 대비 -{:.1f}%)".format(drop_pct))
        elif drop_pct <= 3.0:
            reasons.append("🟡 소폭 하락 (진입가 대비 -{:.1f}%)".format(drop_pct))
        else:
            reasons.append("🔵 과도 하락 (진입가 대비 -{:.1f}%)".format(drop_pct))
            fail_count += 1

    exec_label, _ = _entry_execution_judgement(exec_metrics)
    flow_state = str((exec_metrics or {}).get("flow_state", "중립") or "중립")
    last_active_age_sec = int((exec_metrics or {}).get("last_active_age_sec", 999) or 999)
    if exec_label == "진입 적합":
        reasons.append(f"✅ 체결속도 양호 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
    elif exec_label == "보류 우선":
        reasons.append(f"🔵 체결속도 급약화 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
        fail_count += 1
    elif exec_label == "참고":
        reasons.append(f"🟡 체결속도 예비판단 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
    else:
        reasons.append(f"🟡 체결속도 보통 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")

    if stop and price and entry:
        stop_distance_pct = (price - stop) / price * 100
        if stop_distance_pct >= 2.0:
            reasons.append(f"✅ 손절가까지 여유 ({stop_distance_pct:.1f}%)")
        elif stop_distance_pct >= 1.0:
            reasons.append(f"🟡 손절가 접근 중 ({stop_distance_pct:.1f}%)")
        else:
            reasons.append(f"🔵 손절가 근접 ({stop_distance_pct:.1f}%)")
            fail_count += 1

    sector_ok = True
    try:
        _s_theme = watch.get("sector_theme", "")
        if _s_theme and _s_theme != "기타업종":
            for _tk, _ti in THEME_MAP.items():
                if _tk == _s_theme or _s_theme in _ti.get("desc", ""):
                    _chg_list = []
                    for _sc, _sn in _ti.get("stocks", [])[:5]:
                        try:
                            _sp = get_stock_price(_sc)
                            _cr = _sp.get("change_rate", 0)
                            if _cr is not None:
                                _chg_list.append(float(_cr))
                            time.sleep(0.03)
                        except Exception:
                            continue
                    if _chg_list and (sum(_chg_list) / len(_chg_list)) <= -1.0:
                        sector_ok = False
                    break
    except Exception:
        pass
    if sector_ok:
        reasons.append("✅ 섹터 모멘텀 유지")
    else:
        reasons.append("🔵 섹터 모멘텀 이탈")
        fail_count += 1

    if fail_count >= 2:
        decision = "금지"
        detail = "구조 악화 — 추가매수 금지, 기존 보유분 유지 또는 감축 검토"
    elif fail_count == 1:
        decision = "보류"
        detail = "일부 조건 미충족 — 추가매수 보류, 상황 관찰"
    else:
        decision = "가능"
        detail = "조건 충족 — 추가진입 가능"

    return {"decision": decision, "reasons": reasons, "detail": detail, "fail_count": fail_count}


def _entry_execution_status_block(code: str, price: int = 0, metrics: dict | None = None, fallback_metrics: dict | None = None) -> str:
    current_metrics = metrics or get_execution_speed_metrics(code, current_price=price) or {}
    if not current_metrics and not fallback_metrics:
        return ""
    base_metrics = current_metrics if (current_metrics.get("ready") or current_metrics.get("provisional")) else (fallback_metrics or current_metrics)
    if not base_metrics:
        return ""
    speed_score = int(base_metrics.get("execution_speed_score", 0) or 0)
    dip_score = int(base_metrics.get("dip_resilience_score", 0) or 0)
    filtered_ratio = float(base_metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0) * 100.0
    flow_state = str(base_metrics.get("flow_state", "중립") or "중립")
    freshness_age = int(base_metrics.get("last_active_age_sec", 999) or 999)
    speed_label = _execution_score_label(speed_score)
    dip_label = _execution_score_label(dip_score)
    judgement_label, judgement_line = _entry_execution_judgement(base_metrics)
    if current_metrics.get("ready"):
        return (
            "━━━━━━━━━━━━━━━\n"
            f"⚡ <b>진입 시 체결속도</b>  {speed_score}점 ({speed_label})\n"
            f"🪨 눌림 유지  {dip_score}점 ({dip_label})\n"
            f"🧹 미세체결 제외  {filtered_ratio:.0f}%\n"
            f"🚦 최근 흐름  {flow_state}  / 최근 유효체결 {freshness_age}초 전\n"
            f"🧭 <b>{judgement_label}</b>  — {judgement_line.replace('✅ ', '').replace('⚠️ ', '').replace('🟡 ', '')}\n"
        )
    if current_metrics.get("provisional"):
        return (
            "━━━━━━━━━━━━━━━\n"
            f"⚡ <b>진입 시 체결속도</b>  예비판단 {speed_score}점 ({speed_label})\n"
            f"🪨 예비 눌림 유지  {dip_score}점 ({dip_label})\n"
            f"🧹 예비 미세체결 제외  {filtered_ratio:.0f}%\n"
            f"🚦 최근 흐름  {flow_state}  / 최근 유효체결 {freshness_age}초 전\n"
            f"🧭 <b>참고</b>  — 현재 샘플이 충분하진 않지만 최근 유효 체결 {int(current_metrics.get('valid_samples', 0) or 0)}개 기준 참고값입니다. 진입 전 호가를 한 번 더 확인하세요.\n"
        )
    if fallback_metrics and (fallback_metrics.get("ready") or fallback_metrics.get("provisional")):
        ref_prefix = "포착시"
        ref_mode = "예비판단" if fallback_metrics.get("provisional") and not fallback_metrics.get("ready") else "체결속도"
        return (
            "━━━━━━━━━━━━━━━\n"
            f"⚡ <b>진입 시 체결속도</b>  현재 샘플 부족 (참고)\n"
            f"📌 {ref_prefix} {ref_mode}  {speed_score}점 ({speed_label})\n"
            f"🪨 {ref_prefix} 눌림 유지  {dip_score}점 ({dip_label})\n"
            f"🧹 {ref_prefix} 미세체결 제외  {filtered_ratio:.0f}%\n"
            f"🚦 {ref_prefix} 흐름  {flow_state}  / 최근 유효체결 {freshness_age}초 전\n"
            f"🧭 <b>참고</b>  — 현재 샘플이 부족해 포착시 체결 기준으로 표시합니다. 진입 전 호가를 한 번 더 확인하세요.\n"
        )
    return (
        "━━━━━━━━━━━━━━━\n"
        f"⚡ <b>진입 시 체결속도</b>  샘플 부족 ({judgement_label})\n"
        f"{judgement_line}\n"
    )

def _entry_execution_confirmation_threshold(signal_type: str) -> tuple[int, int]:
    sig = str(signal_type or "")
    if sig in FAST_EXECUTION_SIGNAL_TYPES:
        return EXEC_SPEED_CONFIRM_MIN_SCORE_FAST, EXEC_SPEED_CONFIRM_MIN_DIP_SCORE
    if sig in ENTRY_EXECUTION_SIGNAL_TYPES:
        return EXEC_SPEED_CONFIRM_MIN_SCORE_ENTRY, max(45, EXEC_SPEED_CONFIRM_MIN_DIP_SCORE - 10)
    return 0, 0


def _apply_execution_speed_to_signal(s: dict, mode: str | None = None) -> dict:
    if not isinstance(s, dict):
        return s
    code = normalize_stock_code(s.get("code"))
    if not code:
        return s
    signal_type = str(s.get("signal_type", "") or "")
    metrics = get_execution_speed_metrics(code, current_price=safe_int(s.get("price", 0), 0))
    s["execution_metrics"] = metrics
    reasons = list(s.get("reasons") or [])
    cautions = list(s.get("cautions") or [])

    if metrics.get("ready"):
        speed_score = int(metrics.get("execution_speed_score", 0) or 0)
        dip_score = int(metrics.get("dip_resilience_score", 0) or 0)
        filtered_ratio = float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0)
        speed_label = _execution_score_label(speed_score)
        dip_label = _execution_score_label(dip_score)
        flow_state = str(metrics.get("flow_state", "중립") or "중립")
        freshness_age = int(metrics.get("last_active_age_sec", 999) or 999)
        reasons.append(f"⚡ 체결지속속도 {speed_score}점 ({speed_label})")
        reasons.append(f"🪨 눌림 유지 {dip_score}점 ({dip_label})  (미세체결 제외 {filtered_ratio*100:.0f}%)")
        reasons.append(f"🚦 최근 체결흐름 {flow_state} / 최근 유효체결 {freshness_age}초 전")
        if signal_type in FAST_EXECUTION_SIGNAL_TYPES:
            s["entry_execution_focus"] = True
            if speed_score >= 75:
                s["score"] = int(s.get("score", 0) or 0) + 6
            elif speed_score >= 60:
                s["score"] = int(s.get("score", 0) or 0) + 3
            elif speed_score < 35:
                s["score"] = int(s.get("score", 0) or 0) - 2
                cautions.append("⚠️ 체결지속속도 약함 — 추격보다 진입가 도달 후 재확인")
            if dip_score >= 75:
                s["score"] = int(s.get("score", 0) or 0) + 4
            elif dip_score < 35:
                s["score"] = int(s.get("score", 0) or 0) - 1
                cautions.append("⚠️ 하락 중 체결 유지 약함 — 진입 시 보수 확인")
            suggested_entry = safe_int(metrics.get("suggested_entry_price", 0), 0)
            if suggested_entry > 0:
                s["execution_hint_entry_price"] = suggested_entry
        elif signal_type in ENTRY_EXECUTION_SIGNAL_TYPES:
            if speed_score >= 65:
                s["score"] = int(s.get("score", 0) or 0) + 4
            elif speed_score < 40:
                s["score"] = int(s.get("score", 0) or 0) - 2
            if dip_score >= 65:
                s["score"] = int(s.get("score", 0) or 0) + 3
                reasons.append("✅ 하락 중에도 체결속도 유지 확인")
            elif dip_score < 40:
                cautions.append("⚠️ 눌림 구간 체결 유지 약함")
        elif signal_type in MID_EXECUTION_SIGNAL_TYPES:
            if speed_score >= 70:
                s["score"] = int(s.get("score", 0) or 0) + 2
            elif speed_score < 35:
                s["score"] = int(s.get("score", 0) or 0) - 1
    else:
        flow_state = str(metrics.get("flow_state", "중립") or "중립")
        freshness_age = int(metrics.get("last_active_age_sec", 999) or 999)
        if signal_type in FAST_EXECUTION_SIGNAL_TYPES:
            if metrics.get("provisional"):
                reasons.append(f"⚡ 체결지속속도 예비 {int(metrics.get('execution_speed_score', 0) or 0)}점 / 흐름 {flow_state} / 최근 유효체결 {freshness_age}초 전")
            else:
                reasons.append("⚡ 체결지속속도 샘플 부족 (참고용)")
            s["entry_execution_focus"] = True
        elif signal_type in ENTRY_EXECUTION_SIGNAL_TYPES:
            if metrics.get("provisional"):
                reasons.append(f"⚡ 체결속도 예비 {int(metrics.get('execution_speed_score', 0) or 0)}점 / 흐름 {flow_state}")
            else:
                reasons.append("⚡ 체결속도 참고 샘플 부족")

    s.pop("execution_setup_required", None)
    if cautions:
        s["cautions"] = cautions
        s["reasons"] = reasons + cautions
    else:
        s["reasons"] = reasons
    return s


def _build_execution_speed_block(s: dict) -> str:
    metrics = (s or {}).get("execution_metrics") or {}
    if not metrics:
        return ""
    if not metrics.get("ready"):
        if s.get("entry_execution_focus") or s.get("execution_setup_required"):
            return "━━━━━━━━━━━━━━━\n⚡ <b>체결지속속도</b>  샘플 부족 (참고)\n🧭 진입가 도달 시 체결 유지 여부를 다시 확인합니다.\n"
        return ""
    filtered = float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0) * 100.0
    speed_score = int(metrics.get('execution_speed_score', 0) or 0)
    dip_score = int(metrics.get('dip_resilience_score', 0) or 0)
    flow_state = str(metrics.get('flow_state', '중립') or '중립')
    freshness_age = int(metrics.get('last_active_age_sec', 999) or 999)
    lines = [
        f"⚡ <b>체결지속속도</b>  {speed_score}점 ({_execution_score_label(speed_score)})",
        f"🪨 눌림 유지  {dip_score}점 ({_execution_score_label(dip_score)})",
        f"🧹 미세체결 제외  {filtered:.0f}%",
        f"🚦 최근 흐름  {flow_state} / 최근 유효체결 {freshness_age}초 전",
    ]
    if s.get("execution_setup_required"):
        lines.append("🧭 하락 중 속도 유지 확인 후 진입가를 확정합니다.")
    elif s.get("entry_execution_focus"):
        lines.append("🧭 포착은 유지하고, 진입가 도달 시 체결 품질을 더 중요하게 봅니다.")
    return "━━━━━━━━━━━━━━━\n" + "\n".join(lines) + "\n"

def _register_execution_setup_watch(s: dict) -> None:
    code = normalize_stock_code(s.get("code"))
    if not code:
        return
    existing_watch = _latest_entry_watch_by_code(code)
    if isinstance(existing_watch, dict) and (existing_watch.get("entry_hit") or existing_watch.get("entry_hit_locked")):
        print(f"  🔒 체결확인 대기 생략: {_resolve_stock_name(code, s.get('name', code))} (이미 대표 진입 확정)")
        return
    removed_existing = False
    for old_key, watch in list(_execution_setup_watch.items()):
        if normalize_stock_code(watch.get("code")) == code:
            _execution_setup_watch.pop(old_key, None)
            removed_existing = True
    metrics = dict(s.get("execution_metrics") or {})
    now_dt = datetime.now()
    log_key = f"{code}_{now_dt.strftime('%Y%m%d%H%M')}"
    signal_log_key = str(s.get("signal_log_key") or "").strip()
    detect_date = str(s.get("detect_date") or "").strip()
    detect_time = str(s.get("detect_time") or "").strip()
    try:
        _detected_at = s.get("detected_at")
        if isinstance(_detected_at, datetime):
            signal_log_key = signal_log_key or f"{code}_{_detected_at.strftime('%Y%m%d%H%M')}"
            if not detect_date:
                detect_date = _detected_at.strftime('%Y%m%d')
            if not detect_time:
                detect_time = _detected_at.strftime('%H:%M:%S')
    except Exception:
        signal_log_key = signal_log_key or ""
    if not detect_date:
        detect_date = now_dt.strftime('%Y%m%d')
    if not detect_time:
        detect_time = now_dt.strftime('%H:%M:%S')
    if not signal_log_key:
        signal_log_key = log_key
    _execution_setup_watch[log_key] = {
        "code": code,
        "name": s.get("name", code),
        "signal_type": s.get("signal_type", ""),
        "price": safe_int(s.get("price", 0), 0),
        "change_rate": safe_float(s.get("change_rate", 0.0), 0.0),
        "volume_ratio": safe_float(s.get("volume_ratio", 0.0), 0.0),
        "entry_price": safe_int(s.get("entry_price", 0), 0),
        "planned_entry_price": safe_int(s.get("planned_entry_price", s.get("entry_price", 0)), 0),
        "stop_loss": safe_int(s.get("stop_loss", 0), 0),
        "target_price": safe_int(s.get("target_price", 0), 0),
        "sector_theme": s.get("sector_info", {}).get("theme", ""),
        "reasons": list(s.get("reasons") or []),
        "registered_ts": time.time(),
        "expire_ts": time.time() + EXEC_SPEED_SETUP_EXPIRE_SEC,
        "detect_date": detect_date,
        "detect_time": detect_time,
        "market_basis": str(s.get("market_basis", s.get("market", "")) or ""),
        "peak_price": max(safe_int(s.get("price", 0), 0), safe_int(metrics.get("recent_peak_price", 0), 0)),
        "last_price": safe_int(s.get("price", 0), 0),
        "signal_log_key": signal_log_key,
        "execution_metrics": metrics,
    }
    _exec_speed_prewarm[code] = time.time()   # ★ 포착 즉시 체결속도 스냅샷 워밍 시작
    _save_execution_setup_watch()
    print(f"  ⚡ 체결확인 대기 등록: {s.get('name', code)} [{s.get('signal_type','')}] 예상진입 {safe_int(s.get('entry_price',0),0):,}원")


def _update_signal_log_execution_confirmed(log_key: str | None, watch: dict, entry_price: int, stop_price: int, target_price: int,
                                          metrics: dict | None, hit_time: str, hit_price: int) -> None:
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception:
        return
    if not isinstance(data, dict):
        return
    target_key = ""
    if log_key and log_key in data:
        target_key = log_key
    if not target_key:
        for _k, rec in data.items():
            if not isinstance(rec, dict):
                continue
            if normalize_stock_code(rec.get("code")) != normalize_stock_code(watch.get("code")):
                continue
            if rec.get("signal_type") != watch.get("signal_type"):
                continue
            if rec.get("status") not in ("진입준비", "추적중"):
                continue
            target_key = _k
    if not target_key:
        return
    _merge_tracking_episode_records(data, watch.get("code"), target_key, reason="체결확정_대표레코드통합")
    rec = data.get(target_key) or {}
    rec["status"] = "추적중"
    rec["episode_representative"] = True
    rec["entry_price"] = int(entry_price)
    rec["stop_price"] = int(stop_price)
    rec["target_price"] = int(target_price)
    rec["entry_hit"] = True
    rec["entry_hit_price"] = int(hit_price)
    rec["entry_hit_time"] = hit_time
    if " " in hit_time:
        rec["entry_hit_date"], rec["entry_hit_clock"] = hit_time.split(" ", 1)
    rec["execution_setup_confirmed"] = True
    rec["execution_setup_confirm_time"] = hit_time
    rec.setdefault("feature_snapshot", {})
    if isinstance(metrics, dict):
        rec["feature_snapshot"]["execution_speed_score"] = int(metrics.get("execution_speed_score", 0) or 0)
        rec["feature_snapshot"]["dip_resilience_score"] = int(metrics.get("dip_resilience_score", 0) or 0)
        rec["feature_snapshot"]["micro_trade_filtered_ratio"] = float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0)
        rec["feature_snapshot"]["execution_pullback_pct"] = float(metrics.get("pullback_pct", 0.0) or 0.0)
    _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)


def _register_active_entry_watch_from_confirmation(watch: dict, entry_price: int, stop_price: int, target_price: int,
                                                   hit_price: int, hit_time: str, persist: bool = True) -> None:
    code = normalize_stock_code(watch.get("code"))
    if not code:
        return
    for old_key, old_watch in list(_entry_watch.items()):
        if normalize_stock_code((old_watch or {}).get("code")) != code:
            continue
        archived_watch = _entry_watch.pop(old_key, None)
        if archived_watch:
            _archive_entry_watch_record(old_key, archived_watch, consume_reason="체결확정_대표진입승계", final_status="대표진입승계")
    key = f"{code}_{datetime.now().strftime('%Y%m%d%H%M%S')}_active"
    _entry_watch[key] = {
        "code": code,
        "name": watch.get("name", code),
        "entry_price": int(entry_price),
        "stop_loss": int(stop_price),
        "target_price": int(target_price),
        "signal_type": watch.get("signal_type", ""),
        "signal_log_key": watch.get("signal_log_key", ""),
        "detect_date": str(watch.get("detect_date", "") or ""),
        "detect_time": watch.get("detect_time", datetime.now().strftime("%H:%M")),
        "last_notified_ts": time.time(),
        "notify_count": 1,
        "miss_count": 0,
        "registered_ts": time.time(),
        "expire_ts": time.time() + 86400 * MAX_CARRY_DAYS,
        "peak_price": max(int(hit_price), safe_int(watch.get("peak_price", 0), 0)),
        "reasons": list(watch.get("reasons") or [])[:5],
        "sector_theme": watch.get("sector_theme", ""),
        "execution_metrics": dict(watch.get("execution_metrics") or {}),
        "entry_watch_state": "active",
        "entry_hit": True,
        "entry_hit_locked": True,
        "entry_hit_time": hit_time,
        "entry_hit_price": int(hit_price),
        "entry_hit_date": hit_time.split(" ", 1)[0] if " " in hit_time else "",
        "entry_hit_clock": hit_time.split(" ", 1)[1] if " " in hit_time else "",
    }
    if persist:
        _save_entry_watch_active()


def _build_execution_confirmation_message(watch: dict, entry_price: int, stop_price: int, target_price: int,
                                         hit_price: int, hit_time: str, metrics: dict | None = None) -> str:
    metrics = metrics or {}
    rr_text = _calc_rr_text(entry_price, stop_price, target_price)
    stop_pct = round((stop_price - entry_price) / entry_price * 100, 1) if entry_price else 0.0
    target_pct = round((target_price - entry_price) / entry_price * 100, 1) if entry_price else 0.0
    sig_type = str(watch.get("signal_type", "") or "")
    sig_label = get_signal_label(sig_type, watch.get("signal_type", ""))
    change_at_detect = safe_float(watch.get("change_at_detect", watch.get("change_rate", 0.0)), 0.0)
    volume_ratio = safe_float(watch.get("volume_ratio", 0.0), 0.0)
    pattern_stats = watch.get("similar_pattern_stats") or _get_similar_pattern_stats(
        watch.get("code", ""), sig_type, change_at_detect, volume_ratio
    )
    pattern_summary = _build_similar_pattern_summary_block(pattern_stats)
    lines = [
        "⚡ <b>[체결속도 확인 → 진입 확정]</b>",
        "━━━━━━━━━━━━━━━",
        f"🔴 <b>{watch.get('name','')}</b>  <code>{watch.get('code','')}</code>",
        f"원신호: {sig_label}  |  포착: {_format_capture_datetime_label(detect_date=watch.get('detect_date',''), detect_time=watch.get('detect_time',''))}  |  확정: {hit_time.split(' ',1)[-1] if ' ' in hit_time else hit_time}",
    ]
    if pattern_summary:
        lines.append(pattern_summary)
    lines.extend([
        "━━━━━━━━━━━━━━━",
        f"⚡ 체결지속속도 {int(metrics.get('execution_speed_score', 0) or 0)}점",
        f"🪨 눌림 유지 {int(metrics.get('dip_resilience_score', 0) or 0)}점",
        "━━━━━━━━━━━━━━━",
        "┌─────────────────────",
        "│ ⚡️ <b>하락 중 속도 유지 확인</b>",
        f"│ 📍 현재가  <b>{hit_price:,}원</b>",
        f"│ 🎯 확정 진입가  <b>{entry_price:,}원</b>",
        f"│ 🛡 손절가  <b>{stop_price:,}원</b>  ({stop_pct:+.1f}%)",
        f"│ 🏆 목표가  <b>{target_price:,}원</b>  ({target_pct:+.1f}%)",
        f"│ ⚖️ 손익비  <b>{rr_text}</b>",
        "└─────────────────────",
    ])
    return "\n".join(lines)



def check_execution_setup_watch() -> None:
    if not _execution_setup_watch:
        return
    expired = []
    state_snapshot_changed = False
    structure_changed = False
    active_changed = False
    for key, watch in list(_execution_setup_watch.items()):
        try:
            if time.time() >= float(watch.get("expire_ts", 0) or 0):
                _record_entry_miss(watch, "체결확인만료", int(watch.get("last_price", 0) or watch.get("entry_price", 0) or 0))
                expired.append(key)
                continue
            cur = get_stock_price(watch.get("code"))
            price = safe_int((cur or {}).get("price", 0), 0)
            if not price:
                continue
            if price != safe_int(watch.get("last_price", 0), 0):
                watch["last_price"] = price
                state_snapshot_changed = True
            if price > safe_int(watch.get("peak_price", 0), 0):
                watch["peak_price"] = price
                state_snapshot_changed = True
            metrics = get_execution_speed_metrics(watch.get("code"), current_price=price)
            if metrics != watch.get("execution_metrics"):
                watch["execution_metrics"] = metrics
                state_snapshot_changed = True
            min_speed, min_dip = _entry_execution_confirmation_threshold(watch.get("signal_type"))
            pullback_pct = float(metrics.get("pullback_pct", 0.0) or 0.0)
            if not metrics.get("ready"):
                continue
            if pullback_pct < EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT or pullback_pct > EXEC_SPEED_CONFIRM_MAX_PULLBACK_PCT:
                continue
            if int(metrics.get("execution_speed_score", 0) or 0) < min_speed:
                continue
            if int(metrics.get("dip_resilience_score", 0) or 0) < min_dip:
                continue
            if float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0) > EXEC_SPEED_FILTER_MAX_RATIO:
                continue
            entry_price = _round_price_down(min(price, safe_int(metrics.get("suggested_entry_price", price), price) or price))
            if entry_price <= 0:
                entry_price = _round_price_down(price)
            stop_price, target_price, _, _, _ = calc_stop_target(watch.get("code"), entry_price, signal_type=watch.get("signal_type"))
            if stop_price <= 0 or target_price <= entry_price:
                continue
            hit_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            _update_signal_log_execution_confirmed(watch.get("signal_log_key"), watch, entry_price, stop_price, target_price, metrics, hit_time, price)
            _register_active_entry_watch_from_confirmation(watch, entry_price, stop_price, target_price, price, hit_time, persist=False)
            active_changed = True
            send_with_chart_buttons(
                _build_execution_confirmation_message(watch, entry_price, stop_price, target_price, price, hit_time, metrics),
                watch.get("code", ""), watch.get("name", "")
            )
            print(f"  ⚡ 진입 확정: {watch.get('name','')} {price:,} / 확정진입 {entry_price:,}")
            expired.append(key)
        except Exception:
            continue
    for key in expired:
        if key in _execution_setup_watch:
            _execution_setup_watch.pop(key, None)
            structure_changed = True
    if active_changed:
        _save_entry_watch_active()
    if structure_changed:
        _save_execution_setup_watch(force=True)
    elif state_snapshot_changed:
        _save_execution_setup_watch(force=False)

def _iter_signal_log_records(data) -> list:
    if isinstance(data, dict):
        return [v for v in data.values() if isinstance(v, dict)]
    if isinstance(data, list):
        return [v for v in data if isinstance(v, dict)]
    return []


def _get_tracking_elapsed_days(rec: dict, today: str | None = None) -> int:
    today = str(today or datetime.now().strftime("%Y%m%d"))
    detect_date = str(rec.get("detect_date", "") or "").strip()
    if not detect_date:
        return 999
    try:
        return (datetime.strptime(today, "%Y%m%d") - datetime.strptime(detect_date, "%Y%m%d")).days
    except Exception:
        return 999


def _is_tracking_display_expired(rec: dict, today: str | None = None) -> bool:
    if not isinstance(rec, dict):
        return True
    if rec.get("status") != "추적중":
        return True
    return _get_tracking_elapsed_days(rec, today) >= TRACK_MAX_DAYS


def _is_empty_tracking_price_triplet(entry_price: int | float | None, stop_price: int | float | None, target_price: int | float | None) -> bool:
    return (not safe_int(entry_price, 0) and
            not safe_int(stop_price, 0) and
            not safe_int(target_price, 0))


def _is_orphan_carry_snapshot(info: dict | None) -> bool:
    if not isinstance(info, dict):
        return False
    return _is_empty_tracking_price_triplet(
        info.get("entry_price", info.get("entry", 0)),
        info.get("stop_loss", info.get("stop_price", info.get("stop", 0))),
        info.get("target_price", info.get("target", 0)),
    )


def _parse_compact_datetime(value) -> datetime | None:
    if isinstance(value, datetime):
        return value
    value = str(value or "").strip()
    if not value:
        return None
    for fmt in ("%Y%m%d%H%M%S", "%Y-%m-%d %H:%M:%S", "%Y%m%d", "%Y-%m-%d"):
        try:
            return datetime.strptime(value, fmt)
        except Exception:
            continue
    return None


def _build_latest_tracking_by_code(data: dict | None = None) -> dict[str, dict]:
    latest_by_code = {}
    latest_key_by_code = {}
    for rec in _iter_signal_log_records(data):
        code = normalize_stock_code(rec.get("code") or rec.get("stock_code") or rec.get("종목코드"))
        if not code:
            continue
        key = f"{rec.get('detect_date', '')}{rec.get('detect_time', '')}{rec.get('status', '')}"
        if key >= latest_key_by_code.get(code, ""):
            latest_by_code[code] = rec
            latest_key_by_code[code] = key
    return latest_by_code


def _is_active_carry_snapshot(info: dict | None, latest_rec: dict | None = None, today: str | None = None) -> bool:
    if not isinstance(info, dict):
        return False
    if _is_orphan_carry_snapshot(info):
        return False

    carry_day = safe_int(info.get("carry_day", 0), 0)
    if carry_day < 0 or carry_day >= MAX_CARRY_DAYS:
        return False

    detected_at = _parse_compact_datetime(info.get("detected_at"))
    if detected_at is not None:
        stale_days = max(MAX_CARRY_DAYS + 1, TRACK_MAX_DAYS)
        if (datetime.now() - detected_at).days >= stale_days:
            return False

    if latest_rec is None:
        return True
    if not isinstance(latest_rec, dict):
        return False
    if latest_rec.get("status") != "추적중":
        return False
    if _is_orphan_tracking(latest_rec):
        return False
    if _is_tracking_display_expired(latest_rec, today):
        return False
    return True


def _sanitize_carry_snapshot_map(raw_data, siglog_data: dict | None = None) -> tuple[dict, set[str]]:
    latest_by_code = _build_latest_tracking_by_code(siglog_data)
    today = datetime.now().strftime("%Y%m%d")
    dropped_codes = set()
    sanitized = {}

    if isinstance(raw_data, dict):
        items = list(raw_data.items())
    elif isinstance(raw_data, list):
        items = []
        for item in raw_data:
            if not isinstance(item, dict):
                continue
            code = normalize_stock_code(item.get("code") or item.get("stock_code") or item.get("종목코드"))
            items.append((code, item))
    else:
        items = []

    for raw_code, info in items:
        if not isinstance(info, dict):
            continue
        code = normalize_stock_code(info.get("code") or raw_code)
        if not code:
            continue
        latest_rec = latest_by_code.get(code)
        if not _is_active_carry_snapshot(info, latest_rec=latest_rec, today=today):
            dropped_codes.add(code)
            continue
        snap = dict(info)
        snap["code"] = code
        sanitized[code] = snap

    return sanitized, dropped_codes



def _is_actionable_entry_watch(watch: dict | None, latest_rec: dict | None = None, now_ts: float | None = None) -> bool:
    watch = watch if isinstance(watch, dict) else {}
    if not (watch.get("entry_hit") or watch.get("entry_hit_locked")):
        return False
    state = str(watch.get("entry_watch_state", "active") or "active").lower()
    if state not in ("active", "watching", "pending"):
        return False
    now_ts = float(now_ts or time.time())
    expire_ts = float(watch.get("expire_ts", 0) or 0)
    if expire_ts and now_ts >= expire_ts:
        return False
    if latest_rec is not None:
        if not isinstance(latest_rec, dict):
            return False
        status = str(latest_rec.get("status", "") or "")
        if status not in TRACK_ACTIVE_STATUSES:
            return False
        if latest_rec.get("actual_entry") is not True and latest_rec.get("entry_hit") is not True:
            return False
    return True


def _collect_actionable_position_limit_codes(siglog_data: dict | None = None, today: str | None = None) -> set[str]:
    """동시보유 제한에 실제로 반영할 '행동 가능한' 감시 코드를 수집.
    v62: 단순 carry/_detected_stocks 전체가 아니라 entry_watch / execution_setup_watch /
    최근 active signal_log로 연결된 코드 중심으로 계산해 stale 감시 잔존 때문에
    신규 리더가 전부 position_limit에 막히는 현상을 줄인다.
    """
    actionable_codes: set[str] = set()
    today = str(today or datetime.now().strftime("%Y%m%d"))
    now_ts = time.time()
    latest_by_code = _build_latest_tracking_by_code(siglog_data)

    # [v65] entry_watch 중 만료 안 된 + entry_hit 또는 도달 가능한 것만 카운트
    try:
        for watch in list((_entry_watch or {}).values()):
            if not isinstance(watch, dict):
                continue
            state = str(watch.get("entry_watch_state", "active") or "active").lower()
            if state not in ("active", "watching", "pending"):
                continue
            # 만료된 감시는 제외
            expire_ts = float(watch.get("expire_ts", 0) or 0)
            if expire_ts and now_ts >= expire_ts:
                continue
            # entry_hit 된 것(진입가 도달)만 실제 보유로 카운트
            # 아직 도달 안 된 건 "대기 중"이지 "보유 중"이 아님
            code = normalize_stock_code(watch.get("code") or watch.get("stock_code") or watch.get("종목코드"))
            latest_rec = latest_by_code.get(code) if code else None
            if _is_actionable_entry_watch(watch, latest_rec=latest_rec, now_ts=now_ts) and code:
                actionable_codes.add(code)
    except Exception:
        pass

    # execution_setup_watch도 진입 확정된 것만
    try:
        for watch in list((_execution_setup_watch or {}).values()):
            if not isinstance(watch, dict):
                continue
            # 체결 확정된 것만 보유로 카운트
            if watch.get("confirmed") or watch.get("entry_hit"):
                code = normalize_stock_code(watch.get("code") or watch.get("stock_code") or watch.get("종목코드"))
                if code:
                    actionable_codes.add(code)
    except Exception:
        pass

    # signal_log에서 실제 "추적중" + entry_hit 완료된 것만 (대기 중인 건 제외)
    try:
        carry_raw = _read_json_safe(CARRY_FILE, {})
        if isinstance(carry_raw, dict):
            for raw_code in carry_raw:
                code = normalize_stock_code(raw_code)
                if code:
                    rec = latest_by_code.get(code)
                    if isinstance(rec, dict) and rec.get("status") in TRACK_ACTIVE_STATUSES:
                        if rec.get("entry_hit") and not _is_orphan_tracking(rec):
                            actionable_codes.add(code)
    except Exception:
        pass

    return actionable_codes


def _record_capture_funnel_event(event_type: str, signal: dict | None = None, extra: dict | None = None) -> None:
    event_type = str(event_type or "").strip().lower()
    if event_type not in {"saved", "watch", "reached"}:
        return
    today = datetime.now().strftime("%Y%m%d")
    try:
        data = _read_json_safe(CAPTURE_FUNNEL_FILE, {})
        if not isinstance(data, dict):
            data = {}
        row = data.get(today) if isinstance(data.get(today), dict) else {}
        row = dict(row)
        row.setdefault("saved", 0)
        row.setdefault("watch", 0)
        row.setdefault("reached", 0)
        row[event_type] = safe_int(row.get(event_type, 0), 0) + 1
        if isinstance(signal, dict):
            row["last_code"] = normalize_stock_code(signal.get("code") or row.get("last_code") or "")
            row["last_name"] = str(signal.get("name") or row.get("last_name") or "")
            row["last_signal_type"] = str(signal.get("signal_type") or row.get("last_signal_type") or "")
        if isinstance(extra, dict) and extra:
            row["last_extra"] = dict(extra)
        row["updated_at"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        data[today] = row
        _write_json_atomic(CAPTURE_FUNNEL_FILE, data, indent=2)
    except Exception:
        pass


def _get_capture_funnel_summary(day: str | None = None) -> dict:
    day = str(day or datetime.now().strftime("%Y%m%d"))
    try:
        data = _read_json_safe(CAPTURE_FUNNEL_FILE, {})
    except Exception:
        data = {}
    if not isinstance(data, dict):
        data = {}
    row = data.get(day) if isinstance(data.get(day), dict) else {}
    row = dict(row)
    saved = safe_int(row.get("saved", 0), 0)
    watch = safe_int(row.get("watch", 0), 0)
    reached = safe_int(row.get("reached", 0), 0)
    return {
        "day": day,
        "saved": saved,
        "watch": watch,
        "reached": reached,
        "watch_ratio": round(watch / saved, 3) if saved > 0 else 0.0,
        "reach_ratio": round(reached / watch, 3) if watch > 0 else 0.0,
        "updated_at": str(row.get("updated_at") or ""),
    }


def _get_capture_watch_recovery_state(signal: dict | None = None, day: str | None = None) -> dict:
    summary = _get_capture_funnel_summary(day=day)
    saved = safe_int(summary.get("saved", 0), 0)
    watch = safe_int(summary.get("watch", 0), 0)
    reached = safe_int(summary.get("reached", 0), 0)
    active = False
    reason = ""
    if saved >= 8 and watch >= max(5, int(saved * 0.6)) and reached == 0:
        active = True
        reason = "watch_reach_zero"
    elif saved >= 10 and watch >= 6 and reached <= 1 and (reached / max(1, watch)) <= 0.08:
        active = True
        reason = "watch_reach_collapse"
    out = dict(summary)
    out["active"] = bool(active)
    out["reason"] = reason
    if isinstance(signal, dict):
        out["code"] = normalize_stock_code(signal.get("code") or "")
        out["signal_type"] = str(signal.get("signal_type") or "")
    return out


def _should_skip_next_open_signal_record(rec: dict, today: str | None = None) -> bool:
    if not isinstance(rec, dict):
        return True
    status = str(rec.get("status", "") or "")
    exit_reason = str(rec.get("exit_reason", "") or "")
    if status == TRACK_TIMEOUT_RESULT or exit_reason == "고아추적_자동만료":
        return True
    if status == "추적중" and (_is_orphan_tracking(rec) or _is_tracking_display_expired(rec, today)):
        return True
    return False


def _sanitize_next_open_watchlist_codes(codes: list, carry_data=None, siglog_data=None) -> list:
    today = datetime.now().strftime("%Y%m%d")
    latest_by_code = {}
    latest_key_by_code = {}
    for rec in _iter_signal_log_records(siglog_data):
        code = normalize_stock_code(rec.get("code") or rec.get("stock_code") or rec.get("종목코드"))
        if not code:
            continue
        key = f"{rec.get('detect_date','')}{rec.get('detect_time','')}"
        if key >= latest_key_by_code.get(code, ""):
            latest_by_code[code] = rec
            latest_key_by_code[code] = key

    orphan_carry_codes = set()
    if isinstance(carry_data, dict):
        for raw_code, info in carry_data.items():
            code = normalize_stock_code(raw_code)
            if code and _is_orphan_carry_snapshot(info):
                orphan_carry_codes.add(code)
    elif isinstance(carry_data, list):
        for item in carry_data:
            if not isinstance(item, dict):
                continue
            code = normalize_stock_code(item.get("code") or item.get("stock_code") or item.get("종목코드"))
            if code and _is_orphan_carry_snapshot(item):
                orphan_carry_codes.add(code)

    cleaned = []
    seen = set()
    for raw_code in codes or []:
        code = normalize_stock_code(raw_code)
        if not code or code in seen:
            continue
        latest = latest_by_code.get(code)
        if latest and _should_skip_next_open_signal_record(latest, today):
            continue
        if code in orphan_carry_codes and not latest:
            continue
        seen.add(code)
        cleaned.append(code)
    return cleaned


def build_next_open_watchlist(max_codes: int = 30) -> dict:
    """장 종료 후: 내일 감시할 워치리스트를 생성해서 파일로 저장."""
    # 우선순위: carry_stocks → 최근 signal_log 종목 → (있으면) universe.json
    carry = _read_json_safe(os.path.join(DATA_DIR, "carry_stocks.json"), {})
    siglog = _read_json_safe(os.path.join(DATA_DIR, "signal_log.json"), {})
    universe = _read_json_safe(os.path.join(DATA_DIR, "universe.json"), {})

    codes = []
    seen = set()

    def _push(raw_code):
        c = normalize_stock_code(raw_code)
        if c and c not in seen:
            seen.add(c)
            codes.append(c)

    # carry_stocks 구조가 dict/list 어떤 형태든 대응
    if isinstance(carry, dict):
        for k, info in carry.items():
            if isinstance(info, dict) and _is_orphan_carry_snapshot(info):
                continue
            _push(k)
    elif isinstance(carry, list):
        for item in carry:
            if isinstance(item, dict) and _is_orphan_carry_snapshot(item):
                continue
            _push(item.get("code") if isinstance(item, dict) else item)

    # 최근 신호/추적 종목
    recs = _iter_signal_log_records(siglog)
    if recs:
        recs.sort(key=lambda r: f"{r.get('detect_date','')}{r.get('detect_time','')}", reverse=True)
        for rec in recs[:500]:  # 너무 오래는 보지 않음
            if _should_skip_next_open_signal_record(rec):
                continue
            _push(rec.get("code") or rec.get("stock_code") or rec.get("종목코드"))
            if len(codes) >= max_codes:
                break

    # universe.json (사용자 지정 유니버스가 있으면 보충)
    if isinstance(universe, dict):
        ulist = universe.get("codes") or universe.get("universe") or universe.get("tickers") or []
        if isinstance(ulist, list):
            for u in ulist:
                _push(u)
                if len(codes) >= max_codes:
                    break

    codes = _sanitize_next_open_watchlist_codes(codes, carry_data=carry, siglog_data=siglog)[:max_codes]
    payload = {
        "ts": time.time(),
        "date": datetime.now().strftime("%Y-%m-%d"),
        "max_codes": max_codes,
        "codes": codes,
    }
    try:
        _ensure_dir(DATA_DIR)
        _write_json_atomic(WATCHLIST_NEXT_OPEN_FILE, payload, indent=2)
    except Exception as e:
        print(f"⚠️ 워치리스트 저장 실패: {e}")
    return payload

def _collect_next_open_gap_candidate_codes(max_codes: int = NEXT_OPEN_GAP_POOL_MAX) -> list:
    """익영업일 갭상승 선진입 후보 탐색용 종목 풀을 보수적으로 수집."""
    codes = []
    seen = set()

    def _push(raw_code):
        c = normalize_stock_code(raw_code)
        if c and c not in seen:
            seen.add(c)
            codes.append(c)

    try:
        with _state_lock:
            for c in list((_detected_stocks or {}).keys()):
                _push(c)
            for w in list((_entry_watch or {}).values()):
                if isinstance(w, dict):
                    _push(w.get("code"))
    except Exception:
        pass

    try:
        carry = _read_json_safe(os.path.join(DATA_DIR, "carry_stocks.json"), {})
        if isinstance(carry, dict):
            for k in carry.keys():
                _push(k)
        elif isinstance(carry, list):
            for item in carry:
                _push(item.get("code") if isinstance(item, dict) else item)
    except Exception:
        pass

    siglog = _read_json_safe(SIGNAL_LOG_FILE, {})
    if isinstance(siglog, dict):
        recs = [v for v in siglog.values() if isinstance(v, dict)]
    elif isinstance(siglog, list):
        recs = [v for v in siglog if isinstance(v, dict)]
    else:
        recs = []
    recs.sort(key=lambda r: f"{r.get('detect_date','')}{r.get('detect_time','')}", reverse=True)
    for rec in recs[:300]:
        _push(rec.get("code") or rec.get("stock_code") or rec.get("종목코드"))
        if len(codes) >= max_codes:
            break

    if len(codes) < max_codes:
        try:
            with _state_lock:
                for c in list((_dynamic_candidates or {}).keys()):
                    _push(c)
                    if len(codes) >= max_codes:
                        break
        except Exception:
            pass

    if len(codes) < max_codes:
        try:
            for c, _n, _d in get_all_scan_candidates() or []:
                _push(c)
                if len(codes) >= max_codes:
                    break
        except Exception:
            pass

    if len(codes) < max_codes:
        try:
            base = build_next_open_watchlist(max_codes=max_codes).get("codes", [])
            for c in base:
                _push(c)
                if len(codes) >= max_codes:
                    break
        except Exception:
            pass
    return codes[:max_codes]


def _latest_signal_record_by_code(code: str, records: list) -> dict | None:
    code = normalize_stock_code(code)
    if not code:
        return None
    latest = None
    latest_key = ""
    for rec in records or []:
        if not isinstance(rec, dict):
            continue
        rc = normalize_stock_code(rec.get("code") or rec.get("stock_code") or rec.get("종목코드"))
        if rc != code:
            continue
        k = f"{rec.get('detect_date','')}{rec.get('detect_time','')}"
        if k >= latest_key:
            latest = rec
            latest_key = k
    return latest


def _round_price_down(price: float) -> int:
    try:
        return int(float(price) / 10) * 10
    except Exception:
        return int(price or 0)


def _build_preclose_gap_entry_plan(code: str, current_price: int, change_rate: float, stage: str) -> dict | None:
    code = normalize_stock_code(code)
    current_price = int(current_price or 0)
    if not code or current_price <= 0:
        return None
    try:
        atr_pct = float(calc_atr_pct(code, current_price, fallback_pct=2.5) or 2.5)
    except Exception:
        atr_pct = 2.5

    if change_rate >= 20:
        base_pullback = 1.6
    elif change_rate >= 12:
        base_pullback = 1.2
    elif change_rate >= 6:
        base_pullback = 0.9
    elif change_rate >= 3:
        base_pullback = 0.7
    else:
        base_pullback = 0.6
    if stage == "nxt":
        base_pullback += 0.2

    atr_pullback = max(0.5, min(atr_pct * 0.4, 1.6))
    pullback_pct = min(max(max(base_pullback, atr_pullback), 0.6), 2.2)
    entry_price = _round_price_down(current_price * (1 - pullback_pct / 100.0))
    if entry_price <= 0 or entry_price >= current_price:
        entry_price = _round_price_down(current_price * 0.995)
    if entry_price <= 0 or entry_price >= current_price:
        return None

    stop_price, target_price, stop_pct, target_pct, atr_used = calc_stop_target(code, entry_price, signal_type="PRECLOSE_GAP_ENTRY")
    if stop_price <= 0 or target_price <= entry_price:
        return None
    if current_price >= target_price:
        return None

    risk = max(entry_price - stop_price, 1)
    reward = max(target_price - entry_price, 0)
    rr = round(reward / risk, 2) if risk > 0 else 0.0
    entry_away_pct = round((current_price - entry_price) / entry_price * 100, 2) if entry_price else 0.0
    if rr < PRECLOSE_GAP_MIN_RR:
        return None
    if entry_away_pct > PRECLOSE_GAP_MAX_ENTRY_AWAY_PCT:
        return None

    return {
        "entry_price": int(entry_price),
        "stop_loss": int(stop_price),
        "target_price": int(target_price),
        "stop_pct": float(stop_pct),
        "target_pct": float(target_pct),
        "rr": rr,
        "entry_away_pct": entry_away_pct,
        "pullback_pct": round(pullback_pct, 2),
        "atr_used": bool(atr_used),
    }


def _score_next_open_gap_candidate(code: str, stage: str, latest_rec: dict | None,
                                   us: dict, strong_dart_codes: set) -> dict | None:
    code = normalize_stock_code(code)
    if not code:
        return None

    use_nxt = bool(stage == "nxt" and is_nxt_open() and is_nxt_listed(code))
    if use_nxt:
        cur = get_nxt_stock_price(code) or get_stock_price(code)
        market_note = "NXT 기준"
    else:
        cur = get_stock_price(code)
        market_note = "KRX 기준"
    if not cur:
        return None

    name = _resolve_stock_name(code, cur.get("name", ""), cur)
    if is_scoring_only_instrument(code, name):
        return None

    price = int(cur.get("price", 0) or 0)
    high = int(cur.get("high", 0) or 0)
    change_rate = float(cur.get("change_rate", 0.0) or 0.0)
    volume_ratio = float(cur.get("volume_ratio", 0.0) or 0.0)
    if price <= 0:
        return None

    score = 0
    reasons = []
    cautions = []

    if change_rate >= 20:
        score += 20; reasons.append("🔥 강한 시세 유지 +20")
    elif change_rate >= 12:
        score += 16; reasons.append("🔥 장후반 강세 유지 +16")
    elif change_rate >= 6:
        score += 10; reasons.append("📈 종가 강도 우수 +10")
    elif change_rate >= 3:
        score += 5; reasons.append("📈 종가 강도 양호 +5")

    if price and high:
        close_ratio = price / max(high, 1)
        if close_ratio >= 0.99:
            score += 9; reasons.append("📌 고가권 유지 +9")
        elif close_ratio >= 0.975:
            score += 5; reasons.append("📌 고가 근처 유지 +5")

    if volume_ratio >= 10:
        score += 12; reasons.append(f"💥 거래량 {volume_ratio:.1f}배 +12")
    elif volume_ratio >= 4:
        score += 8; reasons.append(f"💥 거래량 {volume_ratio:.1f}배 +8")
    elif volume_ratio >= 2:
        score += 4; reasons.append(f"📊 거래량 {volume_ratio:.1f}배 +4")

    try:
        sector_info = calc_sector_momentum(code, name) or {}
    except Exception:
        sector_info = {}
    sector_bonus = int(sector_info.get("bonus", 0) or 0)
    if sector_bonus >= 20:
        score += 12; reasons.append("🏭 섹터 모멘텀 강함 +12")
    elif sector_bonus >= 10:
        score += 8; reasons.append("🏭 섹터 모멘텀 우호 +8")
    elif sector_bonus >= 5:
        score += 4; reasons.append("🏭 섹터 동조화 +4")

    leader = sector_info.get("leader") or {}
    if leader and str(leader.get("code", "")) == str(code):
        score += 4; reasons.append("👑 섹터 대장주 +4")

    if latest_rec:
        rec_score = int(latest_rec.get("score", 0) or 0)
        if latest_rec.get("detect_date") == datetime.now().strftime("%Y%m%d"):
            if rec_score >= 80:
                score += 10; reasons.append(f"🧪 당일 포착 강도 {rec_score}점 +10")
            elif rec_score >= 65:
                score += 6; reasons.append(f"🧪 당일 포착 강도 {rec_score}점 +6")
        if latest_rec.get("entry_hit"):
            score += 4; reasons.append("🎯 진입가 도달 이력 +4")

    score, reasons, similar_pattern_stats = _apply_similar_pattern_score(
        score, reasons, code, "PRECLOSE_GAP_ENTRY", change_rate, volume_ratio, weight_mode="strong"
    )
    similar_pattern_summary = _build_similar_pattern_summary_block(similar_pattern_stats)

    gap_signal = str(us.get("gap_signal", "flat") or "flat")
    if gap_signal == "gap_up":
        score += 6; reasons.append("🌐 미국시장 갭상승 우호 +6")
    elif gap_signal == "gap_down":
        score -= 6; cautions.append("🌐 미국시장 갭하락 경계 -6")
    nasdaq_chg = float(us.get("nasdaq_chg", 0.0) or 0.0)
    if nasdaq_chg >= 1.0:
        score += 2; reasons.append("🧠 나스닥 강세 +2")
    elif nasdaq_chg <= -1.5:
        score -= 2; cautions.append("🧠 나스닥 약세 -2")

    if code in strong_dart_codes:
        score += 8; reasons.append("📢 강재료 공시 +8")
    try:
        dart_risk = check_dart_risk(code)
        if isinstance(dart_risk, dict) and dart_risk.get("is_risk"):
            score -= 12
            title = str(dart_risk.get("title", "") or "")[:22]
            cautions.append(f"⚠️ DART 리스크 -12 ({title})")
    except Exception:
        pass

    if use_nxt:
        try:
            krx_ref = get_stock_price(code) or {}
            krx_change = float(krx_ref.get("change_rate", change_rate) or change_rate)
            if change_rate >= krx_change + 1.0:
                score += 5; reasons.append(f"🔴 NXT 추가 강세 +5 ({change_rate:+.1f}%)")
            elif change_rate <= krx_change - 1.0:
                score -= 4; cautions.append(f"🔵 NXT 탄력 둔화 -4 ({change_rate:+.1f}%)")
        except Exception:
            pass

    plan = _build_preclose_gap_entry_plan(code, price, change_rate, stage)
    if not plan:
        return None
    rr = float(plan.get("rr", 0.0) or 0.0)
    entry_away_pct = float(plan.get("entry_away_pct", 0.0) or 0.0)
    if rr >= 2.0:
        score += 10; reasons.append(f"⚖️ 손익비 {rr:.1f} +10")
    elif rr >= 1.6:
        score += 6; reasons.append(f"⚖️ 손익비 {rr:.1f} +6")
    else:
        score += 3; reasons.append(f"⚖️ 손익비 {rr:.1f} +3")

        msg += (
            f"  📌 현재가 {int(item.get('current_price',0) or 0):,}원  ({float(item.get('change_rate', 0.0) or 0.0):+.1f}%)\n"
            f"  ℹ️ 실제 진입가는 선진입가 도달 알림에서만 제공합니다.  ·  {item.get('market_note','KRX 기준')}\n"
        )
        cautions.append(f"⏰ 진입가까지 {entry_away_pct:.1f}% 여유")

    score = int(round(score))
    min_score = NEXT_OPEN_GAP_MIN_SCORE - (2 if stage == "nxt" else 0)
    if score < min_score:
        return None

    sig_type = latest_rec.get("signal_type", "") if latest_rec else ""
    return {
        "code": code,
        "name": name,
        "score": score,
        "similar_pattern_stats": similar_pattern_stats,
        "similar_pattern_summary": similar_pattern_summary,
        "signal_type": PRECLOSE_GAP_SIGNAL_TYPE,
        "origin_signal_type": sig_type,
        "current_price": price,
        "change_rate": round(change_rate, 1),
        "volume_ratio": round(volume_ratio, 1),
        "sector_theme": sector_info.get("theme", "") if isinstance(sector_info, dict) else "",
        "sector_summary": sector_info.get("summary", "") if isinstance(sector_info, dict) else "",
        "sector_info": sector_info if isinstance(sector_info, dict) else {},
        "market_note": market_note,
        "reasons": reasons[:5],
        "cautions": cautions[:2],
        "entry_price": int(plan["entry_price"]),
        "stop_loss": int(plan["stop_loss"]),
        "target_price": int(plan["target_price"]),
        "stop_pct": float(plan["stop_pct"]),
        "target_pct": float(plan["target_pct"]),
        "rr": rr,
        "entry_away_pct": entry_away_pct,
        "pullback_pct": float(plan["pullback_pct"]),
        "atr_used": bool(plan["atr_used"]),
        "gap_signal": gap_signal,
        "market_basis": "NXT" if use_nxt else "KRX",
    }


def build_next_open_gap_candidates(stage: str = "krx", max_items: int = NEXT_OPEN_GAP_MAX_SHOW) -> dict:
    """장후반/NXT 후반 기준 익영업일 갭상승 선진입 후보를 점수화해 저장."""
    stage = "nxt" if str(stage).lower() == "nxt" else "krx"
    stage_label = "1차 선별" if stage == "krx" else "최종 보정"
    signal_data = _read_json_safe(SIGNAL_LOG_FILE, {})
    if isinstance(signal_data, dict):
        signal_records = [v for v in signal_data.values() if isinstance(v, dict)]
    elif isinstance(signal_data, list):
        signal_records = [v for v in signal_data if isinstance(v, dict)]
    else:
        signal_records = []

    active_preclose_codes = set()
    today = datetime.now().strftime("%Y%m%d")
    for rec in signal_records:
        if (normalize_stock_code(rec.get("code"))
                and rec.get("signal_type") == PRECLOSE_GAP_SIGNAL_TYPE
                and rec.get("detect_date") == today
                and rec.get("status") == "추적중"
                and rec.get("entry_hit")):
            active_preclose_codes.add(normalize_stock_code(rec.get("code")))

    us = get_us_market_signals() or {}
    strong_dart_codes = set()
    try:
        for item in _scan_recent_dart_materials(days_back=1, max_items=20):
            c = normalize_stock_code(item.get("code"))
            if c:
                strong_dart_codes.add(c)
    except Exception:
        pass

    candidates = []
    pool_codes = list(_collect_next_open_gap_candidate_codes(max_codes=NEXT_OPEN_GAP_POOL_MAX) or [])
    for code in pool_codes:
        code = normalize_stock_code(code)
        if not code or code in active_preclose_codes:
            continue
        latest_rec = _latest_signal_record_by_code(code, signal_records)
        try:
            scored = _score_next_open_gap_candidate(code, stage, latest_rec, us, strong_dart_codes)
            if scored:
                candidates.append(scored)
        except Exception:
            continue
        time.sleep(0.05)

    candidates.sort(key=lambda x: (x.get("score", 0), x.get("rr", 0), x.get("change_rate", 0), x.get("volume_ratio", 0)), reverse=True)
    payload = {
        "ts": time.time(),
        "date": datetime.now().strftime("%Y-%m-%d"),
        "time": datetime.now().strftime("%H:%M"),
        "stage": stage,
        "stage_label": stage_label,
        "market_basis": "NXT" if stage == "nxt" else "KRX",
        "us_gap_signal": us.get("gap_signal", "flat"),
        "pool_count": len(pool_codes),
        "candidate_count": len(candidates),
        "codes": [c.get("code") for c in candidates[:max_items]],
        "candidates": candidates[:max_items],
    }
    try:
        _ensure_dir(DATA_DIR)
        _write_json_atomic(NEXT_OPEN_GAP_FILE, payload, indent=2)
    except Exception as e:
        print(f"⚠️ 익영업일 선진입 후보 저장 실패: {e}")
    return payload


def _upsert_preclose_gap_signal(candidate: dict, stage: str) -> str:
    """PRECLOSE_GAP_ENTRY 신호를 signal_log에 저장/업데이트해서 학습 데이터화."""
    now_dt = datetime.now()
    stock = {
        "code": candidate.get("code"),
        "name": candidate.get("name", ""),
        "signal_type": PRECLOSE_GAP_SIGNAL_TYPE,
        "detected_at": now_dt,
        "price": int(candidate.get("current_price", 0) or 0),
        "change_rate": float(candidate.get("change_rate", 0.0) or 0.0),
        "volume_ratio": float(candidate.get("volume_ratio", 0.0) or 0.0),
        "score": int(candidate.get("score", 0) or 0),
        "grade": "A" if int(candidate.get("score", 0) or 0) >= 80 else "B",
        "entry_price": int(candidate.get("entry_price", 0) or 0),
        "stop_loss": int(candidate.get("stop_loss", 0) or 0),
        "target_price": int(candidate.get("target_price", 0) or 0),
        "atr_used": bool(candidate.get("atr_used", False)),
        "sector_info": candidate.get("sector_info") or {},
        "reasons": list(candidate.get("reasons") or []),
        "position": {"pct": 6.0},
        "execution_setup_required": True,
        "execution_metrics": dict(candidate.get("execution_metrics") or {}),
        "gap_entry_meta": {
            "stage": stage,
            "stage_label": candidate.get("stage_label", "1차 선별" if stage == "krx" else "최종 보정"),
            "market_basis": candidate.get("market_basis", "KRX"),
            "entry_away_pct": float(candidate.get("entry_away_pct", 0.0) or 0.0),
            "rr": float(candidate.get("rr", 0.0) or 0.0),
            "pullback_pct": float(candidate.get("pullback_pct", 0.0) or 0.0),
            "gap_signal": candidate.get("gap_signal", "flat"),
            "origin_signal_type": candidate.get("origin_signal_type", ""),
        },
    }

    data = _read_json_safe(SIGNAL_LOG_FILE, {})
    if not isinstance(data, dict):
        data = {}
    today = now_dt.strftime("%Y%m%d")
    existing_key = ""
    for _k, rec in data.items():
        if not isinstance(rec, dict):
            continue
        if (normalize_stock_code(rec.get("code")) == normalize_stock_code(stock["code"])
                and rec.get("signal_type") == PRECLOSE_GAP_SIGNAL_TYPE
                and rec.get("detect_date") == today
                and rec.get("status") == "추적중"):
            existing_key = _k
            break

    if not existing_key:
        save_signal_log(stock)
        new_key = f"{stock['code']}_{now_dt.strftime('%Y%m%d%H%M')}"
        data = _read_json_safe(SIGNAL_LOG_FILE, {})
        if isinstance(data, dict) and new_key in data and isinstance(data.get(new_key), dict):
            rec = data.get(new_key) or {}
            rec["gap_entry_meta"] = stock.get("gap_entry_meta", {})
            rec["feature_snapshot"] = rec.get("feature_snapshot", {}) or {}
            rec["feature_snapshot"].update({
                "price": stock["price"],
                "change_rate": stock["change_rate"],
                "volume_ratio": stock["volume_ratio"],
                "sector_theme": stock.get("sector_info", {}).get("theme", ""),
                "sector_bonus": stock.get("sector_info", {}).get("bonus", 0),
            })
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        return new_key

    rec = data.get(existing_key) or {}
    rec["name"] = stock["name"]
    rec["score"] = stock["score"]
    rec["grade"] = stock["grade"]
    rec["detect_price"] = stock["price"]
    rec["change_at_detect"] = stock["change_rate"]
    rec["volume_ratio"] = stock["volume_ratio"]
    rec["entry_price"] = stock["entry_price"]
    rec["stop_price"] = stock["stop_loss"]
    rec["target_price"] = stock["target_price"]
    rec["atr_used"] = stock["atr_used"]
    rec["sector_bonus"] = stock.get("sector_info", {}).get("bonus", 0)
    rec["sector_theme"] = stock.get("sector_info", {}).get("theme", "")
    rec["gap_entry_meta"] = stock.get("gap_entry_meta", {})
    rec.setdefault("feature_snapshot", {})
    rec["feature_snapshot"].update({
        "price": stock["price"],
        "change_rate": stock["change_rate"],
        "volume_ratio": stock["volume_ratio"],
        "sector_theme": stock.get("sector_info", {}).get("theme", ""),
        "sector_bonus": stock.get("sector_info", {}).get("bonus", 0),
    })
    _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
    return existing_key


def register_preclose_gap_watch(candidate: dict, signal_log_key: str) -> None:
    """장마감 전까지만 유효한 선진입 전용 감시 등록."""
    code = normalize_stock_code(candidate.get("code"))
    if not code:
        return
    stage = "nxt" if str(candidate.get("stage", "krx")).lower() == "nxt" else "krx"
    now = _now_kst()
    deadline_clock = dtime(20, 0) if stage == "nxt" else dtime(15, 30)
    deadline_ts = datetime.combine(now.date(), deadline_clock, tzinfo=_KST).timestamp()
    key = f"{code}_{stage}_{now.strftime('%Y%m%d%H%M')}"

    for old_key, watch in list(_preclose_gap_entry_watch.items()):
        if not isinstance(watch, dict):
            continue
        if normalize_stock_code(watch.get("code")) == code and str(watch.get("stage", "")) == stage:
            _preclose_gap_entry_watch.pop(old_key, None)

    _preclose_gap_entry_watch[key] = {
        "code": code,
        "name": candidate.get("name", ""),
        "signal_type": PRECLOSE_GAP_SIGNAL_TYPE,
        "stage": stage,
        "stage_label": candidate.get("stage_label", "1차 선별" if stage == "krx" else "최종 보정"),
        "market_basis": candidate.get("market_basis", "NXT" if stage == "nxt" else "KRX"),
        "entry_price": int(candidate.get("entry_price", 0) or 0),
        "stop_loss": int(candidate.get("stop_loss", 0) or 0),
        "target_price": int(candidate.get("target_price", 0) or 0),
        "current_price": int(candidate.get("current_price", 0) or 0),
        "score": int(candidate.get("score", 0) or 0),
        "rr": float(candidate.get("rr", 0.0) or 0.0),
        "change_rate": float(candidate.get("change_rate", 0.0) or 0.0),
        "volume_ratio": float(candidate.get("volume_ratio", 0.0) or 0.0),
        "reasons": list(candidate.get("reasons") or []),
        "sector_info": candidate.get("sector_info") or {},
        "registered_ts": time.time(),
        "deadline_ts": deadline_ts,
        "detect_time": now.strftime("%H:%M"),
        "peak_price": int(candidate.get("current_price", 0) or 0),
        "signal_log_key": signal_log_key,
        "execution_setup_required": True,
        "execution_metrics": dict(candidate.get("execution_metrics") or {}),
    }
    _save_preclose_gap_entry_watch()


def _send_preclose_gap_entry_hit_message(watch: dict, hit_price: int, use_nxt: bool = False) -> None:
    entry = int(watch.get("entry_price", 0) or 0)
    stop = int(watch.get("stop_loss", 0) or 0)
    target = int(watch.get("target_price", 0) or 0)
    rr = float(watch.get("rr", 0.0) or 0.0)
    stop_pct = round((stop - entry) / entry * 100, 1) if entry else 0.0
    target_pct = round((target - entry) / entry * 100, 1) if entry else 0.0
    market_tag = "\n📡 <b>NXT 기준 가격</b>" if use_nxt else ""
    reasons_block = ""
    if watch.get("reasons"):
        reasons_block = "\n" + "\n".join(f"  {r}" for r in list(watch.get("reasons") or [])[:3]) + "\n"
    pattern_summary_top = str(watch.get("similar_pattern_summary", "") or "").strip()
    pattern_summary_block = (pattern_summary_top + "\n") if pattern_summary_top else ""
    send_with_chart_buttons(
        f"🎯 <b>[선진입가 도달!]</b>{market_tag}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🔴 <b>{watch.get('name','')}</b>  <code>{watch.get('code','')}</code>\n"
        f"{pattern_summary_block}"
        f"원신호: 종가선진입  |  포착: {_format_capture_datetime_label(detect_date=watch.get('detect_date',''), detect_time=watch.get('detect_time',''))}  |  {watch.get('market_basis','KRX')}\n"
        f"{reasons_block}"
        f"━━━━━━━━━━━━━━━\n"
        f"┌─────────────────────\n"
        f"│ ⚡️ <b>오늘 선진입 구간 도달</b>\n"
        f"│ 📍 현재가  <b>{hit_price:,}원</b>\n"
        f"│ 🎯 선진입가  <b>{entry:,}원</b>\n"
        f"│ 🛡 손절가  <b>{stop:,}원</b>  ({stop_pct:+.1f}%)\n"
        f"│ 🏆 익일 목표  <b>{target:,}원</b>  ({target_pct:+.1f}%)\n"
        f"│ ⚖️ 손익비  <b>1 : {rr:.1f}</b>\n"
        f"└─────────────────────\n"
        f"💡 익영업일 갭상승 기대 선진입 플랜입니다.",
        watch.get("code", ""), watch.get("name", "")
    )


def check_preclose_gap_entry_watch() -> None:
    """장후반 선진입 후보의 실제 진입가 도달 여부를 마감 전까지만 추적."""
    if not _preclose_gap_entry_watch:
        return
    now = _now_kst()
    expired = []
    changed = False
    for key, watch in list(_preclose_gap_entry_watch.items()):
        try:
            stage = "nxt" if str(watch.get("stage", "krx")).lower() == "nxt" else "krx"
            deadline_ts = float(watch.get("deadline_ts", 0) or 0)
            use_nxt = bool(stage == "nxt")
            market_open = is_nxt_open() if use_nxt else is_market_open()
            if time.time() >= deadline_ts or not market_open:
                final_price = int(watch.get("last_price", 0) or watch.get("current_price", 0) or watch.get("entry_price", 0) or 0)
                _record_entry_miss(watch, "종가전미도달", final_price)
                expired.append(key)
                continue

            cur = get_nxt_stock_price(watch["code"]) if use_nxt else get_stock_price(watch["code"])
            if use_nxt and (not cur or not cur.get("price")):
                cur = get_stock_price(watch["code"])
            price = int((cur or {}).get("price", 0) or 0)
            if not price:
                continue
            watch["last_price"] = price
            changed = True
            if price > int(watch.get("peak_price", 0) or 0):
                watch["peak_price"] = price
                changed_active = True
            if price > int(watch.get("entry_price", 0) or 0):
                continue
            metrics = get_execution_speed_metrics(watch.get("code"), current_price=price)
            watch["execution_metrics"] = metrics
            changed = True
            if not metrics.get("ready"):
                continue
            if float(metrics.get("pullback_pct", 0.0) or 0.0) < EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT:
                continue
            if int(metrics.get("execution_speed_score", 0) or 0) < EXEC_SPEED_CONFIRM_MIN_SCORE_FAST:
                continue
            if int(metrics.get("dip_resilience_score", 0) or 0) < EXEC_SPEED_CONFIRM_MIN_DIP_SCORE:
                continue
            if float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0) > EXEC_SPEED_FILTER_MAX_RATIO:
                continue
            entry_price = _round_price_down(min(price, safe_int(metrics.get("suggested_entry_price", price), price) or price))
            if entry_price <= 0:
                entry_price = _round_price_down(price)
            stop_price, target_price, _, _, _ = calc_stop_target(watch.get("code"), entry_price, signal_type=watch.get("signal_type"))
            if stop_price <= 0 or target_price <= entry_price:
                continue
            hit_time = now.strftime("%Y-%m-%d %H:%M:%S")
            _update_signal_log_execution_confirmed(watch.get("signal_log_key"), watch, entry_price, stop_price, target_price, metrics, hit_time, price)
            _register_active_entry_watch_from_confirmation(watch, entry_price, stop_price, target_price, price, hit_time)
            watch["entry_price"] = entry_price
            changed = True
            watch["stop_loss"] = stop_price
            changed = True
            watch["target_price"] = target_price
            changed = True
            _send_preclose_gap_entry_hit_message(watch, price, use_nxt=use_nxt)
            print(f"  🎯 선진입 확정: {watch.get('name','')} {price:,} / 확정진입 {entry_price:,}")
            expired.append(key)
        except Exception:
            continue
    for key in expired:
        _preclose_gap_entry_watch.pop(key, None)
        changed = True
    if changed:
        _save_preclose_gap_entry_watch()


def update_preclose_gap_open_outcomes() -> None:
    """전일 PRECLOSE_GAP_ENTRY 신호의 익일 시초가/갭률을 signal_log에 기록."""
    try:
        if is_holiday() or not is_market_open():
            return
        data = _read_json_safe(SIGNAL_LOG_FILE, {})
        if not isinstance(data, dict):
            return
        today = datetime.now().strftime("%Y%m%d")
        now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        changed = False
        for rec in data.values():
            if not isinstance(rec, dict):
                continue
            if rec.get("signal_type") != PRECLOSE_GAP_SIGNAL_TYPE:
                continue
            detect_date = str(rec.get("detect_date", "") or "")
            if not detect_date or detect_date >= today:
                continue
            if rec.get("next_open_date") == today:
                continue
            code = normalize_stock_code(rec.get("code"))
            if not code:
                continue
            cur = get_stock_price(code)
            if not cur:
                continue
            open_price = int(cur.get("open", 0) or 0)
            if open_price <= 0:
                continue
            entry = int(rec.get("entry_price", 0) or 0)
            rec["next_open_date"] = today
            rec["next_open_eval_time"] = now_s
            rec["next_open_price"] = open_price
            if entry > 0:
                rec["next_open_gap_pct"] = round((open_price - entry) / entry * 100, 2)
                try:
                    day_high = int(cur.get("high", 0) or 0)
                    if day_high > 0:
                        rec["next_open_day_high_pct"] = round((day_high - entry) / entry * 100, 2)
                except Exception:
                    pass
            changed = True
        if changed:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
    except Exception as e:
        print(f"⚠️ preclose gap open outcome 기록 오류: {e}")


def _get_preclose_gap_run_state() -> dict:
    try:
        st = _read_json_safe(PRECLOSE_GAP_RUN_STATE_FILE, {})
        return st if isinstance(st, dict) else {}
    except Exception:
        return {}

def _save_preclose_gap_run_state(state: dict):
    try:
        _write_json_atomic(PRECLOSE_GAP_RUN_STATE_FILE, state if isinstance(state, dict) else {}, indent=2)
    except Exception as e:
        print(f"⚠️ preclose_gap_run_state 저장 오류: {e}")

def _mark_preclose_gap_run(stage: str, status: str, candidate_count: int = 0):
    st = _get_preclose_gap_run_state()
    today = datetime.now().strftime("%Y%m%d")
    stage = "nxt" if str(stage).lower() == "nxt" else "krx"
    st_key = f"{today}_{stage}"
    st[st_key] = {
        "date": today,
        "stage": stage,
        "status": str(status or ""),
        "candidate_count": int(candidate_count or 0),
        "ts": time.time(),
        "time": datetime.now().strftime("%H:%M:%S"),
    }
    _save_preclose_gap_run_state(st)

def _was_preclose_gap_run(stage: str) -> bool:
    st = _get_preclose_gap_run_state()
    today = datetime.now().strftime("%Y%m%d")
    stage = "nxt" if str(stage).lower() == "nxt" else "krx"
    return f"{today}_{stage}" in st

def _maybe_run_preclose_gap_alert_catchup():
    if is_holiday() or not _try_acquire_leader_lock():
        return
    now_t = datetime.now().time()
    try:
        if dtime(14, 45) <= now_t <= dtime(15, 5):
            print("🕒 KRX 선진입 후보 catch-up 점검")
            send_next_open_gap_alert(stage="krx")
    except Exception as e:
        print(f"⚠️ KRX 선진입 후보 catch-up 실패: {e}")
    try:
        if dtime(19, 20) <= now_t <= dtime(19, 35):
            print("🕒 NXT 선진입 후보 catch-up 점검")
            send_next_open_gap_alert(stage="nxt")
    except Exception as e:
        print(f"⚠️ NXT 선진입 후보 catch-up 실패: {e}")

def send_next_open_gap_alert(stage: str = "krx"):
    """장마감 전에 익영업일 갭상승 선진입 후보를 보수적으로 발송."""
    if is_holiday():
        print("⏸ 선진입 후보 스캔 생략 — 공휴일")
        return
    stage = "nxt" if str(stage).lower() == "nxt" else "krx"
    stage_tag = "NXT 19:20" if stage == "nxt" else "KRX 14:45"

    if _was_preclose_gap_run(stage):
        print(f"⏭️ [{stage_tag}] 선진입 후보 스캔 중복 생략 — 오늘 이미 처리됨")
        return

    if stage == "krx" and not is_market_open():
        print(f"⏸ [{stage_tag}] 선진입 후보 스캔 생략 — KRX 장 미운영")
        return
    if stage == "nxt" and not is_nxt_open():
        print(f"⏸ [{stage_tag}] 선진입 후보 스캔 생략 — NXT 장 미운영")
        return

    print(f"🕒 [{stage_tag}] 선진입 후보 스캔 시작")
    payload = build_next_open_gap_candidates(stage=stage, max_items=NEXT_OPEN_GAP_MAX_SHOW)
    cand = payload.get("candidates") or []
    pool_count = int(payload.get("pool_count", 0) or 0)
    candidate_count = int(payload.get("candidate_count", len(cand)) or len(cand))
    if not cand:
        print(f"📭 [{stage_tag}] 후보 0건 (pool={pool_count}, candidate={candidate_count})")
        _mark_preclose_gap_run(stage, status="zero", candidate_count=0)
        return

    for item in cand:
        item["stage"] = stage
        item["stage_label"] = payload.get("stage_label", "1차 선별" if stage == "krx" else "최종 보정")
        item["market_basis"] = payload.get("market_basis", "KRX")
        siglog_key = _upsert_preclose_gap_signal(item, stage=stage)
        if siglog_key:
            register_preclose_gap_watch(item, siglog_key)

    msg = (
        f"🚀 <b>[익영업일 갭상승 선진입 후보]</b>  {payload.get('time','')}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🕒 {payload.get('stage_label','')}  ·  {payload.get('market_basis','KRX')} 기준\n"
    )
    for idx, item in enumerate(cand, 1):
        sim_summary = str(item.get("similar_pattern_summary", "") or "").strip()
        msg += f"\n{idx}) <b>{item.get('name','')}</b>  {item.get('code','')}  <b>{item.get('score',0)}점</b>\n"
        if sim_summary:
            msg += f"  {sim_summary}\n"
        msg += (
            f"  📌 현재가 {int(item.get('current_price',0) or 0):,}원  ({float(item.get('change_rate', 0.0) or 0.0):+.1f}%)\n"
            f"  ℹ️ 실제 진입가는 선진입가 도달 알림에서만 제공합니다.  ·  {item.get('market_note','KRX 기준')}\n"
        )
        for line in item.get("reasons", [])[:3]:
            msg += f"  {line}\n"
        for line in item.get("cautions", [])[:1]:
            msg += f"  {line}\n"
    us = get_us_market_signals() or {}
    summary = str(us.get("summary", "") or "").splitlines()[0].strip()
    if summary:
        msg += f"\n━━━━━━━━━━━━━━━\n🌐 {summary}\n"
    msg += "⚠️ 후보 알림은 참고용입니다. 실제 진입가는 선진입가 도달 알림에서만 제공합니다. 미확인/미도달 시 자동으로 진입미달 처리됩니다."
    send_by_level(msg, level=ALERT_LEVEL_NORMAL)
    _mark_preclose_gap_run(stage, status="sent", candidate_count=len(cand))
    print(f"✅ [{stage_tag}] 선진입 후보 알림 발송 완료 (pool={pool_count}, candidate={candidate_count}, sent={len(cand)})")

def _scan_recent_dart_materials(days_back: int = 1, max_items: int = 6) -> list:
    """비장중/장전용: 최근(오늘+어제) DART 공시 중 '재료(강/매우강)'만 추려서 반환.
    반환: [{code,name,corp_name,title,grade}, ...]
    """
    if not DART_API_KEY:
        return []
    out = []
    try:
        today = datetime.now().strftime("%Y%m%d")
        dates = [today]
        if days_back >= 1:
            yday = (datetime.now() - timedelta(days=1)).strftime("%Y%m%d")
            dates.append(yday)

        # 키워드 우선순위
        strong = DART_KEYWORDS.get("매우강함", []) + DART_KEYWORDS.get("강함", [])
        strong = [k for k in strong if k]

        seen = set()
        for d in dates:
            dart_list = _fetch_dart_list(d) if DART_API_KEY else []
            for it in (dart_list or []):
                title = (it.get("report_nm") or it.get("title") or "").strip()
                code  = normalize_stock_code(it.get("stock_code") or it.get("stock_code") or it.get("stock_code"))
                corp_name = str(it.get("corp_name") or "").strip()
                if not title or not code:
                    continue
                # 리스크 공시는 제외 (손익 방어 쪽에서 따로 처리)
                if any(rk in title for rk in DART_RISK_KEYWORDS):
                    continue
                hit_kw = next((k for k in strong if k in title), None)
                if not hit_kw:
                    continue
                key = (code, title)
                if key in seen:
                    continue
                seen.add(key)
                name = _resolve_stock_name(code, name_hint=corp_name)
                if not name or str(name).strip() == str(code):
                    name = corp_name or name
                grade = "매우강함" if any(k in title for k in DART_KEYWORDS.get("매우강함", [])) else "강함"
                out.append({"code": code, "name": name, "corp_name": corp_name, "title": title, "grade": grade})
                if len(out) >= max_items:
                    return out
    except Exception as e:
        _log_error("_scan_recent_dart_materials", e)
    return out

def _build_preopen_issue_section(max_lines: int = 12) -> str:
    """장전(07:30) 워치리스트에 붙일 '이슈 기반 섹터/종목' 섹션 생성."""
    lines = []
    try:
        # 1) 지정학/거시 이슈(섹터 방향)
        geo = _get_effective_geo_state() or {}
        if geo.get("active") and time.time() - float(geo.get("ts", 0) or 0) < 3600 * 12:
            sec_dirs = geo.get("sector_directions", []) or []
            if not sec_dirs and geo.get("sectors"):
                # sector_directions가 없으면 fallback 생성
                sec_dirs = _build_fallback_sector_directions(geo.get("kws", []) or [], geo.get("sectors") or [])
            # 상승 섹터만 상위 3개
            ups = [sd for sd in sec_dirs if str(sd.get("direction","")) in ("상승","up","positive","bull")]
            if ups:
                lines.append("🌍 이슈(지정학) 기반 유리 섹터")
                for sd in ups[:3]:
                    sec = sd.get("sector","")
                    reason = (sd.get("reason","") or "").strip()
                    stocks = _get_geo_sector_stocks(sec, max_n=3) if sec else []
                    stk = " / ".join([n for c,n in stocks]) if stocks else ""
                    if stk:
                        lines.append(f" • {sec}: {stk}")
                    else:
                        lines.append(f" • {sec}")
                    if reason:
                        lines.append(f"   - {reason}")
        # 2) DART 강재료(전일~금일)
        darts = _scan_recent_dart_materials(days_back=1, max_items=5)
        if darts:
            lines.append("📢 공시(DART) 강재료 후보")
            for d in darts[:5]:
                code = normalize_stock_code(d.get("code") or "") or str(d.get("code") or "").strip()
                nm = str(d.get("name") or d.get("corp_name") or "").strip()
                title = d.get("title","")
                grade = d.get("grade","")
                label = f"{nm}({code})" if nm and code and nm != code else (nm or code)
                if label:
                    lines.append(f" • {label}: {grade} — {title}")
    except Exception:
        pass

    # 길이 제한
    lines = [ln for ln in lines if ln.strip()]
    if not lines:
        return ""
    if len(lines) > max_lines:
        lines = lines[:max_lines] + ["…(생략)"]
    return "\n".join(lines)

def send_preopen_watchlist():
    """익개장 전(07:30) 워치리스트 요약 전송 + 비장중 이슈(지정학/DART) 반영"""
    try:
        data = build_next_open_watchlist(max_codes=30)
        codes = data.get("codes") if isinstance(data, dict) else None
        if not codes:
            return
        # 너무 길면 상위 15개만 표시
        show = codes[:15]
        msg = "⏰ 익개장 전 워치리스트\n" + " / ".join(show)

        # latest next-open gap candidates (saved on prior close / NXT late session)
        try:
            gap_data = _read_json_safe(NEXT_OPEN_GAP_FILE, {})
            gap_cands = gap_data.get("candidates") if isinstance(gap_data, dict) else None
            if gap_cands:
                msg += f"\n\n🚀 전일 종가 선진입 후보 [{str(gap_data.get('stage_label','최신'))}]\n"
                for idx, item in enumerate(gap_cands[:5], 1):
                    msg += (
                        f"  {idx}) {item.get('name','')}({item.get('code','')}) {int(item.get('score',0) or 0)}점"
                        f"  |  진입 {int(item.get('entry_price',0) or 0):,}  손절 {int(item.get('stop_loss',0) or 0):,}  목표 {int(item.get('target_price',0) or 0):,}\n"
                    )
        except Exception:
            pass

        # Fresh overnight risk recap (do not reuse stale saved string)
        try:
            _ov_msg = _build_overnight_risk_alert_message(limit_items=2, include_stats=False)
            if _ov_msg:
                msg += "\n\n" + _ov_msg
        except Exception:
            pass

        # NEW: off-hours issues (geo sectors + DART strong materials)
        try:
            issue_sec = _build_preopen_issue_section()
            if issue_sec:
                msg += "\n\n" + issue_sec
        except Exception:
            pass

        # entry_hit 종목만 별도 리스크 섹션으로 정리 (07:30 방어 파트)
        try:
            risk_lines = []
            with _state_lock:
                watched = list((_detected_stocks or {}).items())
            for _code, w in watched:
                if not isinstance(w, dict) or not w.get("entry_hit"):
                    continue
                _name = _resolve_stock_name(_code, w.get("name", ""))
                risk_score = 0
                points = []
                try:
                    dr = check_dart_risk(_code, _name)
                    if isinstance(dr, dict) and dr.get("is_risk"):
                        risk_score += 60
                        points.append(f"DART:{str(dr.get('title',''))[:24]}")
                except Exception:
                    pass
                try:
                    geo = _geo_event_state or {}
                    if geo.get("active") and time.time() - float(geo.get("ts", 0) or 0) < 3600 * 12:
                        adj = int(geo.get("score_adj", 0) or 0)
                        if adj <= -5:
                            risk_score += 20
                            points.append("지정학")
                except Exception:
                    pass
                try:
                    ketf = get_korea_etf_signals() or {}
                    summary = str(ketf.get("summary", "") or "")
                    if summary and any(kw in summary for kw in ["약세", "하락", "부진", "리스크", "부정"]):
                        risk_score += 10
                        points.append("해외ETF")
                except Exception:
                    pass
                if risk_score > 0:
                    status = w.get("signal_type") or "포착종목"
                    risk_lines.append((risk_score, f"• {_name}({_code}) [{get_signal_label(status, status)}] — {', '.join(points[:3])}"))
            if risk_lines:
                risk_lines.sort(key=lambda x: x[0], reverse=True)
                msg += "\n\n⚠️ 진입가 도달 종목 리스크 점검\n" + "\n".join(line for _, line in risk_lines[:5])
        except Exception:
            pass

        send_by_level(msg, level=ALERT_LEVEL_NORMAL)
    except Exception as e:
        print(f"⚠️ send_preopen_watchlist 오류: {e}")


def _looks_like_placeholder_stock_name(code: str, name_hint: str = "") -> bool:
    nm = str(name_hint or "").strip()
    code = normalize_stock_code(code) or str(code or "").strip()
    if not nm:
        return True
    compact = nm.replace(" ", "")
    if code and compact == code:
        return True
    if compact.isdigit() and len(compact) >= 5:
        return True
    return False


def _resolve_stock_name(code: str, name_hint: str = "", cur: dict | None = None) -> str:
    """종목명이 비어 있거나 코드 placeholder일 때 KRX/NXT 응답 및 runtime 상태로 복구."""
    code = normalize_stock_code(code) or str(code or "").strip()
    try:
        nm = str(name_hint or "").strip()
        if not _looks_like_placeholder_stock_name(code, nm):
            return nm

        if isinstance(cur, dict):
            nm = str(cur.get("name", "") or "").strip()
            if not _looks_like_placeholder_stock_name(code, nm):
                return nm

        try:
            info = get_stock_price(code)
            nm = str((info or {}).get("name", "") or "").strip()
            if not _looks_like_placeholder_stock_name(code, nm):
                return nm
        except Exception:
            pass

        try:
            info = get_nxt_stock_price(code)
            nm = str((info or {}).get("name", "") or "").strip()
            if not _looks_like_placeholder_stock_name(code, nm):
                return nm
        except Exception:
            pass

        try:
            for pool in (_entry_watch, _execution_setup_watch):
                for rec in list((pool or {}).values()):
                    if not isinstance(rec, dict):
                        continue
                    if normalize_stock_code(rec.get("code")) != code:
                        continue
                    nm = str(rec.get("name", "") or "").strip()
                    if not _looks_like_placeholder_stock_name(code, nm):
                        return nm
        except Exception:
            pass

        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
            if isinstance(data, dict):
                for _k, rec in sorted(data.items(), reverse=True):
                    if not isinstance(rec, dict):
                        continue
                    if normalize_stock_code(rec.get("code")) != code:
                        continue
                    nm = str(rec.get("name", "") or "").strip()
                    if not _looks_like_placeholder_stock_name(code, nm):
                        return nm
        except Exception:
            pass
    except Exception:
        pass
    return code or str(name_hint or "").strip()


def _lookup_name_by_code(code: str, name_hint: str = "") -> str:
    """v40.1: 레거시 호출 호환용. 내부적으로 _resolve_stock_name을 사용."""
    return _resolve_stock_name(code, name_hint=name_hint)


def refresh_dynamic_candidates():
    """
    거래량/상한가/NXT 급등 + 실시간 랭킹 상위 종목을 자동 후보군에 편입
    → THEME_MAP에 없는 종목도 포착 가능
    → 08:00~10:00은 더 강하게, 이후 장중은 보수적으로 반영
    """
    if not is_any_market_open():
        build_next_open_watchlist(max_codes=30)
        print("  💤 비장중: 동적 후보군 갱신 스킵 → 익개장 워치리스트 저장")
        return

    try:
        krx_open = is_market_open()
        nxt_open = is_nxt_open()
        rank_mode = _get_rank_market_mode() or "session"

        vol_stocks = get_volume_surge_stocks() if krx_open else []
        upper_stocks = get_upper_limit_stocks() if krx_open else []
        nxt_stocks = get_nxt_surge_stocks() if nxt_open else []
        krx_rank_stocks = _collect_market_rank_candidates("KRX", scan_limit=None, force=False) if krx_open else []
        nxt_rank_stocks = _collect_market_rank_candidates("NXT", scan_limit=None, force=False) if nxt_open else []

        candidates = {}
        excluded_cnt = 0
        early_rank_cnt = 0
        adaptive_cnt = 0
        theme_feedback_cnt = 0
        nxt_post_cnt = 0

        def _put_candidate(item: dict, desc: str):
            nonlocal excluded_cnt, early_rank_cnt, theme_feedback_cnt, nxt_post_cnt, adaptive_cnt
            code = item.get("code")
            if not code:
                return
            name = _resolve_stock_name(code, item.get("name", ""))
            if not is_trade_candidate_name(name):
                excluded_cnt += 1
                return
            if "랭킹후보" in str(desc):
                early_rank_cnt += 1
            if "adaptive_feedback" in str(desc):
                adaptive_cnt += 1
            if "theme_feedback" in str(desc):
                theme_feedback_cnt += 1
            if "NXT장후리더" in str(desc):
                nxt_post_cnt += 1
            prev = candidates.get(code)
            if prev:
                labels = set(str(prev.get("desc", "")).split(" | ")) | {str(desc)}
                prev["name"] = name
                prev["desc"] = " | ".join(sorted(x for x in labels if x))
            else:
                candidates[code] = {"name": name, "desc": desc}

        for item in vol_stocks + upper_stocks + nxt_stocks:
            desc = "NXT자동편입" if str(item.get("market", "")) == "NXT" else "자동편입"
            _put_candidate(item, desc)
        for item in krx_rank_stocks:
            _put_candidate(item, item.get("desc", f"KRX랭킹후보[{rank_mode}]"))
        for item in nxt_rank_stocks:
            _put_candidate(item, item.get("desc", f"NXT랭킹후보[{rank_mode}]"))
        for item in _collect_adaptive_feedback_candidates(existing_codes=candidates.keys()):
            _put_candidate(item, item.get("desc", "adaptive_feedback"))
        for item in _collect_theme_feedback_candidates(existing_codes=candidates.keys()):
            _put_candidate(item, item.get("desc", "theme_feedback"))
        for item in _collect_nxt_postmarket_candidates(existing_codes=candidates.keys()):
            _put_candidate(item, item.get("desc", "NXT장후리더"))

        for code, info in candidates.items():
            if code not in _dynamic_candidates:
                _dynamic_candidates[code] = {"name": info["name"], "desc": info["desc"], "added_ts": time.time()}
            else:
                _dynamic_candidates[code]["name"] = info["name"]
                _dynamic_candidates[code]["desc"] = info["desc"]
                _dynamic_candidates[code]["added_ts"] = time.time()

        krx_rank_source = "fallback" if _rank_api_disabled_today() else "api"
        print(
            f"  🔄 동적 후보군: {len(_dynamic_candidates)}개 종목 "
            f"(제외 {excluded_cnt}개, KRX={len(vol_stocks)+len(upper_stocks)} [{krx_rank_source}], "
            f"NXT={len(nxt_stocks)}, 랭킹후보={early_rank_cnt} [{rank_mode}], 피드백={adaptive_cnt}, 테마피드백={theme_feedback_cnt}, 장후NXT={nxt_post_cnt})"
        )
    except Exception as e:
        print(f"⚠️ 동적 후보군 갱신 오류: {e}")

def get_all_scan_candidates() -> list:
    """
    THEME_MAP + 동적 후보군 합산 → 중복 제거
    반환: [(code, name, desc), ...]
    """
    _ensure_dynamic_candidates_fresh()
    seen = set()
    result = []
    # THEME_MAP 우선
    for theme_info in THEME_MAP.values():
        for c, n in theme_info["stocks"]:
            if c not in seen:
                resolved_name = _resolve_stock_name(c, n)
                if is_trade_candidate_name(resolved_name):
                    seen.add(c); result.append((c, resolved_name, theme_info["desc"]))
    # 동적 후보군 추가 (THEME_MAP에 없는 종목만)
    for code, info in _dynamic_candidates.items():
        if code not in seen:
            resolved_name = _resolve_stock_name(code, info.get("name", ""))
            if is_trade_candidate_name(resolved_name):
                seen.add(code); result.append((code, resolved_name, info["desc"]))
    return result

# ============================================================
# 장중 실시간 눌림목 돌파 감지
# ============================================================
def check_intraday_pullback_breakout(code: str, name: str) -> dict:
    """
    어제까지 눌림 완성 + 오늘 장 중 돌파 실시간 감지
    (일봉 완성 기다리지 않음 → 아주IB투자, 국전약품 같은 케이스 포착)

    조건:
      - 어제까지 일봉: 1차 급등 이후 눌림 패턴 완성
      - 오늘 장 중:  거래량 폭발 (5일 평균 3배 이상)
                     + 현재가 > 어제 종가 (양봉 진행 중)
                     + 상승률 5% 이상 (돌파 신호)
    """
    # 어제까지 데이터로 눌림 패턴 확인 (오늘 제외)
    items = get_daily_data(code, MID_SURGE_LOOKBACK_DAYS + MID_PULLBACK_DAYS_MAX + 5)
    if len(items) < 8:
        return {}

    # 오늘 실시간 데이터
    cur = get_stock_price(code)
    if not cur or not cur.get("price"):
        return {}
    today_price  = cur["price"]
    today_chg    = cur["change_rate"]
    today_vol    = cur["today_vol"]
    vol_ratio    = cur["volume_ratio"]
    intraday_high = safe_int(cur.get("high", today_price), today_price)

    # 어제까지 데이터에서 눌림 패턴 확인
    hist = items[:-1]   # 오늘 제외 (어제까지)
    if len(hist) < 6:
        return {}

    prev_close = hist[-1]["close"]  # 어제 종가

    # 1차 급등 탐색 (어제까지 데이터)
    surge_peak_price = 0; surge_pct = 0; surge_peak_idx = -1
    for i in range(len(hist)-1, max(0, len(hist)-MID_SURGE_LOOKBACK_DAYS)-1, -1):
        candidate_high = hist[i]["high"]
        search_start   = max(0, i - MID_SURGE_LOOKBACK_DAYS)
        lows = [hist[j]["low"] for j in range(search_start, i+1) if hist[j]["low"]]
        if not lows: continue
        base_low = min(lows)
        pct = (candidate_high - base_low) / base_low * 100
        if pct >= _dynamic["mid_surge_min_pct"] and candidate_high > surge_peak_price:
            surge_peak_price = candidate_high; surge_pct = round(pct,1); surge_peak_idx = i

    if surge_peak_idx < 0 or surge_peak_price == 0:
        return {}

    # 눌림 확인 (고점 이후 ~ 어제까지)
    after_peak = hist[surge_peak_idx+1:]
    if not after_peak:
        return {}
    pullback_low  = min(d["low"]  for d in after_peak if d["low"])
    pullback_days = len(after_peak)
    pullback_pct  = round((surge_peak_price - pullback_low) / surge_peak_price * 100, 1)

    if not (_dynamic["mid_pullback_min"] <= pullback_pct <= _dynamic["mid_pullback_max"]):
        return {}
    if not (MID_PULLBACK_DAYS_MIN <= pullback_days <= MID_PULLBACK_DAYS_MAX):
        return {}

    # 거래량 감소 여부
    surge_vols    = [d["vol"] for d in hist[max(0,surge_peak_idx-3):surge_peak_idx+1] if d["vol"]]
    pb_vols       = [d["vol"] for d in after_peak if d["vol"]]
    avg_surge_vol = sum(surge_vols)/len(surge_vols) if surge_vols else 0
    avg_pb_vol    = sum(pb_vols)/len(pb_vols) if pb_vols else 0
    vol_dried     = avg_pb_vol < avg_surge_vol * 0.7 if avg_surge_vol else False

    breakout_mode = today_price > prev_close and today_chg >= 5.0 and vol_ratio >= 3.0
    reclaim_ref_price = max(today_price, intraday_high)
    reclaim_ratio = _calc_pullback_reclaim_ratio(surge_peak_price, pullback_low, reclaim_ref_price)
    rebound_gain_pct = round((today_price - pullback_low) / pullback_low * 100, 1) if pullback_low else 0.0
    resurge_mode = (
        pullback_pct >= MID_RESURGE_MIN_PULLBACK_PCT
        and today_chg >= MID_RESURGE_MIN_TODAY_CHG
        and vol_ratio >= MID_RESURGE_MIN_VOL_RATIO
        and reclaim_ratio >= MID_RESURGE_MIN_RECLAIM_RATIO
        and rebound_gain_pct >= MID_RESURGE_MIN_BOUNCE_PCT
    )
    if not (breakout_mode or resurge_mode):
        return {}

    # 오늘 돌파/재상승 강도
    z    = get_volume_zscore(code, today_vol)
    rs   = get_relative_strength(today_chg)
    ma20 = sum(d["close"] for d in hist[-20:])/20 if len(hist)>=20 else 0
    ma20_dev = round((today_price-ma20)/ma20*100,1) if ma20 else 0

    # 스코어
    score = 0; reasons = []
    if breakout_mode:
        reasons.append(f"⚡️ <b>장중 돌파 감지!</b> (어제까지 눌림 완성 → 오늘 돌파)")
    else:
        reasons.append(f"♻️ <b>재상승 감지!</b> (깊은 눌림 후 거래대금 재유입)")
    if surge_pct >= 40: score+=25; reasons.append(f"🚀 1차 급등 {surge_pct:.0f}% (강력)")
    elif surge_pct >= 25: score+=20; reasons.append(f"📈 1차 급등 {surge_pct:.0f}%")
    else: score+=15; reasons.append(f"📈 1차 급등 {surge_pct:.0f}%")

    if vol_dried: score+=15; reasons.append(f"✅ 눌림 중 거래량 감소 확인 (건강한 조정)")
    else: score+=8; reasons.append(f"🟡 눌림 {pullback_pct:.0f}% ({pullback_days}일간)")

    if 15 <= pullback_pct <= 30: score+=15; reasons.append(f"🎯 황금 눌림 구간 ({pullback_pct:.0f}%)")
    elif pullback_pct < 15: score+=8; reasons.append(f"🟡 얕은 눌림 ({pullback_pct:.0f}%)")
    else: score+=5; reasons.append(f"🟡 깊은 눌림 ({pullback_pct:.0f}%)")

    # 오늘 돌파/재상승 신호 강도
    if breakout_mode:
        if today_chg >= 20: score+=30; reasons.append(f"🚨 오늘 +{today_chg:.0f}% 강력 돌파!")
        elif today_chg >= 10: score+=20; reasons.append(f"🔥 오늘 +{today_chg:.0f}% 돌파")
        else: score+=10; reasons.append(f"📈 오늘 +{today_chg:.1f}% 돌파 시작")
    else:
        if reclaim_ratio >= 0.8: score += 24; reasons.append(f"🚀 눌림 회복률 {reclaim_ratio*100:.0f}% — 재상승 강함")
        elif reclaim_ratio >= 0.65: score += 18; reasons.append(f"♻️ 눌림 회복률 {reclaim_ratio*100:.0f}% — 재상승 진행")
        else: score += 12; reasons.append(f"🟡 눌림 회복률 {reclaim_ratio*100:.0f}% — 재상승 초입")
        reasons.append(f"📈 저점 대비 +{rebound_gain_pct:.1f}% 반등")

    if vol_ratio >= 10: score+=20; reasons.append(f"💥 거래량 {vol_ratio:.0f}배 폭발 (5일 평균 대비)")
    elif vol_ratio >= 5: score+=15; reasons.append(f"💥 거래량 {vol_ratio:.0f}배 급증")
    else: score+=8; reasons.append(f"📊 거래량 {vol_ratio:.1f}배")

    if z >= VOL_ZSCORE_MIN: score+=10; reasons.append(f"📊 거래량 Z-score {z:.1f}σ")
    if rs >= RS_MIN: score+=10; reasons.append(f"💪 코스피 상대강도 {rs:.1f}배")
    if ma20_dev > 0: score+=5; reasons.append(f"📐 20일선 돌파 (+{ma20_dev:.1f}%)")

    score, reasons, similar_pattern_stats = _apply_similar_pattern_score(
        score, reasons, code, "MID_PULLBACK", today_chg, vol_ratio, weight_mode="weak"
    )
    if score < 45:
        return {}

    grade = "A" if score>=80 else "B" if score>=60 else "C"
    if resurge_mode and not breakout_mode:
        entry = _calc_resurge_entry_price(today_price, pullback_low, reclaim_ratio)
        reasons.append(f"↘️ 재상승형 보수 진입가 {entry:,}원 (현재가 추격 방지)")
    else:
        entry = today_price
    stop, target, stop_pct, target_pct, atr_used = calc_stop_target(code, entry, signal_type="MID_PULLBACK")

    result = {
        "code": code, "name": _resolve_stock_name(code, name, cur), "price": today_price, "change_rate": today_chg,
        "volume_ratio": vol_ratio, "signal_type": "MID_PULLBACK",
        "is_intraday": True,   # 장중 돌파 표시
        "grade": grade, "score": score,
        "pattern_score_base": score,
        "surge_pct": surge_pct, "pullback_pct": pullback_pct, "pullback_days": pullback_days,
        "current_pullback": round((surge_peak_price-today_price)/surge_peak_price*100,1),
        "pullback_reclaim_ratio": reclaim_ratio, "resurge_mode": bool(resurge_mode and not breakout_mode),
        "entry_soft_block_allowed": bool(resurge_mode),
        "vol_dried": vol_dried, "vol_recovered": True, "is_bullish": True,
        "ma20_dev": ma20_dev, "rs": rs, "vol_zscore": z,
        "similar_pattern_stats": similar_pattern_stats,
        "entry_price": entry, "stop_loss": stop, "target_price": target,
        "stop_pct": stop_pct, "target_pct": target_pct, "atr_used": atr_used,
        "gap_pct": round(((today_price - prev_close) / prev_close) * 100, 1) if prev_close else 0.0,
        "reasons": reasons, "detected_at": datetime.now(),
    }
    return _finalize_mid_pullback_signal(result)

# ============================================================
# 눌림목 스캐너 — THEME_MAP + 동적 후보군 전체 스캔
# ============================================================
def run_mid_pullback_scan():
    """
    90초마다 전체 후보군 눌림목 체크
    ① 일봉 완성 기준 눌림목 (KRX 장중에만)
    ② KRX 마감 후에도 NXT 급등 종목은 눌림목 체크 계속
    """
    krx_open = is_market_open()
    nxt_open = is_nxt_open()
    if not krx_open and not nxt_open: return
    if _bot_paused: return
    print(f"\n[{datetime.now().strftime('%H:%M:%S')}] 눌림목 스캔{'(NXT포함)' if nxt_open else ''}...", flush=True)

    # 동적 후보군 갱신 (장초반 강하게 / 이후 장중 보수적으로)
    _ensure_dynamic_candidates_fresh()

    all_candidates = get_all_scan_candidates()
    signals = []

    for code, name, theme_desc in all_candidates:
        name = _resolve_stock_name(code, name)
        # [v41.88] 쿨다운 체크: 등급 상향 시 리셋 허용
        _prev_cooldown = _mid_pullback_alert_history.get(code)
        if isinstance(_prev_cooldown, dict):
            _prev_ts = _prev_cooldown.get("ts", 0)
            _prev_grade = str(_prev_cooldown.get("pattern_grade") or _prev_cooldown.get("grade", "C") or "C").upper()
        else:
            _prev_ts = float(_prev_cooldown or 0)
            _prev_grade = "C"
        _in_cooldown = (time.time() - _prev_ts) < MID_ALERT_COOLDOWN
        if _in_cooldown:
            # 쿨다운 내라도 등급 상향 가능성 확인을 위해 분석은 진행
            try:
                _peek = analyze_mid_pullback(code, name)
                if not _peek:
                    _peek = check_intraday_pullback_breakout(code, name)
                if _peek:
                    _peek = _finalize_mid_pullback_signal(_peek)
                    _peek_grade = str(_peek.get("pattern_grade", _peek.get("grade", "C"))).upper()
                    _grade_order = {"A": 3, "B": 2, "C": 1}
                    if _grade_order.get(_peek_grade, 0) > _grade_order.get(_prev_grade, 0):
                        print(f"  🔄 등급 상향 감지: {name} {_prev_grade}→{_peek_grade} — 쿨다운 리셋")
                        # 쿨다운 리셋, 아래 분석으로 계속 진행
                    else:
                        continue  # 등급 동일/하향 → 쿨다운 유지
                else:
                    continue
            except Exception:
                continue
        try:
            # ① 일봉 기준 눌림목
            result = analyze_mid_pullback(code, name)
            if not result:
                # ② 일봉 패턴 미완성이면 장중 돌파 감지로 재시도
                result = check_intraday_pullback_breakout(code, name)
            if result:
                result["theme_desc"] = theme_desc
                sector_info = calc_sector_momentum(code, name)
                result["sector_info"] = sector_info
                _w_sec = _dynamic.get("feat_w_sector", 1.0)
                result["score"] += int(sector_info.get("bonus", 0) * _w_sec)
                result = _finalize_mid_pullback_signal(result)
                signals.append(result)
            time.sleep(0.3)
        except Exception as e:
            print(f"⚠️ 눌림목 오류 ({code}): {e}")
            continue

    if not signals:
        print("  → 눌림목 조건 충족 종목 없음")
        return

    signals = _apply_stale_pullback_quota(signals, stage="run_mid_pullback_scan")
    signals.sort(
        key=lambda x: (
            1 if x.get("leader_priority_hit") else 0,
            0 if x.get("stale_pullback_hit") else 1,
            0 if x.get("stale_replay_penalty_hit") else 1,
            _grade_rank(x.get("grade", "C")),
            int(x.get("score", 0) or 0),
            float(x.get("change_rate", 0) or 0),
        ),
        reverse=True,
    )
    for s in signals[:3]:
        if is_scoring_only_instrument(s.get("code", ""), s.get("name", "")):
            print(f"  ⏭ 점수전용 종목 제외: {s.get('name', s.get('code',''))}")
            continue
        s = _apply_execution_speed_to_signal(s)
        if str(s.get("grade") or "").upper() == "C":
            s = _enrich_mid_pullback_direct_news(s)
        _live = _get_live_quote_for_signal(s)
        _live_price = safe_int((_live or {}).get("price", s.get("price", 0)), 0)
        _entry = safe_int(s.get("entry_price", 0), 0)
        _blocked_reason = ""
        if _entry and _live_price and _live_price >= _entry:
            try:
                _blocked_reason = _detect_entry_block_reason(_live or {}, {"signal_type": s.get("signal_type", "")}, _live_price, _entry)
            except Exception:
                _blocked_reason = ""
        if _blocked_reason:
            if _blocked_reason == "no_ask_liquidity" and _should_soft_allow_no_ask_liquidity(_live or {}, s):
                s["entry_soft_block_allowed"] = True
                s.setdefault("reasons", []).append("⚠️ 현재 호가 매도잔량이 얇아 즉시 체결은 불리할 수 있음 — 관찰/재접근 우선")
                _log_suppressed_alert(
                    s["code"], s["name"],
                    f"눌림목 호가경고(soft) ({_blocked_reason})",
                    s.get("signal_type", ""),
                    {"entry_price": _entry, "blocked_price": _live_price, "change_rate": (_live or {}).get("change_rate", 0), "ask_qty": (_live or {}).get("ask_qty", 0), "bid_qty": (_live or {}).get("bid_qty", 0)}
                )
            else:
                kept_internal = False
                if _blocked_reason == "no_ask_liquidity" and _should_keep_internal_watch_on_no_ask_liquidity(_live or {}, s):
                    kept_internal = _persist_blocked_capture_watch(s, source_label="눌림목", blocked_reason=_blocked_reason)
                _log_suppressed_alert(
                    s["code"], s["name"],
                    f"눌림목 진입 신호 차단 ({_blocked_reason})",
                    s.get("signal_type", ""),
                    {"entry_price": _entry, "blocked_price": _live_price, "change_rate": (_live or {}).get("change_rate", 0), "ask_qty": (_live or {}).get("ask_qty", 0), "bid_qty": (_live or {}).get("bid_qty", 0), "internal_watch_kept": bool(kept_internal)}
                )
                continue
        if _should_suppress_mid_pullback_c_alert(s):
            _log_suppressed_alert(
                s["code"], s["name"],
                "눌림목 C등급 실알림 억제",
                s.get("signal_type", ""),
                {"score": s.get("score", 0), "grade": s.get("grade", ""), "resurge_mode": bool(s.get("resurge_mode")), "direct_news_hit": bool(s.get("direct_news_hit")), "entry_price": s.get("entry_price", 0)}
            )
            promoted = _promote_internal_capture_watch(s, hist_key=s["code"], source_label="눌림목", reason="C등급 실알림 억제 but 선행형 near-A 확증")
            if not promoted:
                save_signal_log(s)
            _mid_pullback_alert_history[s["code"]] = {"ts": time.time(), "pattern_grade": str(s.get("pattern_grade", s.get("grade", "C"))).upper(), "execution_grade": str(s.get("grade", "C")).upper(), "grade": str(s.get("grade", "C")).upper()}
            tag = "[장중돌파]" if s.get("is_intraday") else "[일봉]"
            print(f"  ⏭ 눌림목 {tag}: {s['name']} [{s['grade']}등급] {s['score']}점 — {'실알림 억제/내부감시 자동승격' if promoted else '실알림 억제/내부기록 유지'}")
            continue
        if not _should_send_external_grade_alert(s):
            _logged = _record_internal_only_alert(s["code"], s, f"눌림목 {str(s.get('grade', 'C')).upper()}등급 외부알림 억제(A전용)")
            promoted = _promote_internal_capture_watch(s, hist_key=s["code"], source_label="눌림목", reason=f"{str(s.get('grade','C')).upper()}등급 near-A/체결 확증")
            if _logged and not promoted:
                save_signal_log(s)
            _mid_pullback_alert_history[s["code"]] = {"ts": time.time(), "pattern_grade": str(s.get("pattern_grade", s.get("grade", "C"))).upper(), "execution_grade": str(s.get("grade", "C")).upper(), "grade": str(s.get("grade", "C")).upper()}
            tag = "[장중돌파]" if s.get("is_intraday") else "[일봉]"
            print(f"  ⏭ 눌림목 {tag}: {s['name']} [{s['grade']}등급] {s['score']}점 — {'외부억제/내부감시 자동승격' if promoted else '외부알림 억제/내부기록 유지'}")
            continue
        save_signal_log(s)
        _watch_key = register_entry_watch(s)                     # ★ 대표 진입가 가드 적용 후 진입가 감시 등록
        _merged_phase1 = _maybe_send_immediate_entry_hit_from_signal(s, _watch_key, merge_capture_phase1=True)
        if not _merged_phase1:
            send_mid_pullback_alert(s)
        else:
            _save_entry_watch_active()
        if len(_sector_monitor) < 8 and _needs_sector_resend_for_alert(s):
            _sector_retry_snap = _clone_alert_snapshot_for_sector_retry(s)
            _sector_retry_snap["_alert_sender"] = "mid_pullback"
            start_sector_monitor(s["code"], s["name"], s.get("signal_type",""), s.get("detect_time",""), True, alert_snapshot=_sector_retry_snap)  # ★ 섹터 재안내 조건부 모니터링
        _mid_pullback_alert_history[s["code"]] = {"ts": time.time(), "pattern_grade": str(s.get("pattern_grade", s.get("grade", "C"))).upper(), "execution_grade": str(s.get("grade", "C")).upper(), "grade": str(s.get("grade", "C")).upper()}
        tag = "[장중돌파]" if s.get("is_intraday") else "[일봉]"
        print(f"  ✓ 눌림목 {tag}: {s['name']} [{s['grade']}등급] {s['score']}점")

def send_mid_pullback_alert(s: dict):
    stock_name = _resolve_stock_name(s.get("code", ""), s.get("name", ""))
    s["name"] = stock_name
    grade_emoji = {"A": "🏆", "B": "🥈", "C": "🥉"}.get(s.get("grade"), "📊")
    grade_text = {"A": "A등급 (최우선)", "B": "B등급 (우선)", "C": "C등급 (참고)"}.get(s.get("grade"), "")
    intraday_tag = "  ⚡️ 장중 돌파" if s.get("is_intraday") else ""
    header_override = str(s.get("_header_override", "") or "").strip()
    header_line = header_override if header_override else f"{grade_emoji} <b>[눌림목 진입 신호]</b>  {grade_text}{intraday_tag}"
    capture_label = _format_capture_datetime_label(
        detected_at=s.get("detected_at"),
        detect_date=s.get("detect_date", ""),
        detect_time=s.get("detect_time", "")
    ) or _format_capture_datetime_label(detected_at=datetime.now())
    message = _build_capture_focus_message(s, header_line, capture_label, name_dot="🟣")
    send_with_chart_buttons(message, s["code"], stock_name)


