    if not items and os.getenv("ENABLE_UNIVERSE_FALLBACK", "1") == "1":
        print(f"⚠️ [KIS] 랭킹 응답 비어있음(status={status}, ct={ct}) → KRX 유니버스 후보군으로 대체")
