def _get_code_hash() -> str:
    """v38.3-D3: 현재 실행 코드의 SHA256 해시 (8자리)"""
    try:
        with open(os.path.abspath(__file__), "rb") as f:
            return hashlib.sha256(f.read()).hexdigest()[:8]
    except Exception:
        return "unknown"

